INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f7ee3c98b0941765cee', '位置：酒店位于靠近地铁口，周边有商场，位置优越
服务：一进酒店就有热情的小姐姐接待，送了我们中秋花灯，还介绍周边和酒店游玩的地方
环境：酒店大堂富丽堂皇，正中间是一整面金箔雕刻而成的红楼梦大观园，旁边还有旋转楼梯，很适合打卡拍照。当然最吸人眼球的就数一口的瀑布餐厅，18米双瀑布搭配透明落地窗，分分钟都是大票
房间：这次给我升级了行政套房，有会客区和卧室，喜欢双洗漱台的设计，再也不用和姐妹抢洗漱台啦
需要特别推荐下四楼的博物馆，这里记录了花园酒店的历史，还有世界各地的特色酒店，值得一逛。', '["https://dimg04.c-ctrip.com/images/0232012000cck6wjq1049_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000cckbc6z6E15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000ccka14g1B03_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000cckaf7x91F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000cckaf7zD092_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000cckccen461D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-07', '花园双床房', '双床房', '朋友出游', 245, 5.5053315359323625, 0, 0.0, 4, 1.6094379124341005, 9, '["周边配套", "前台服务", "公共设施"]'::jsonb, '周边配套', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '位置：酒店位于靠近地铁口，周边有商场，位置优越', '位置：酒店位于靠近地铁口，周边有商场，位置优越
