INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f7ee3c98b0941765cf0', '酒店非常有特色，味道也很好闻，宝格丽的洗护用品，4楼还有酒店博物馆，周边吃的也很多，户外泳池也很干净，适合商务，亲子游，前台的Doris也很nice，态度很好', '["https://dimg04.c-ctrip.com/images/0231712000bgj7l7dA116_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000bgjeu80ABA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000bgja1hr51CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-20', '花园双床房', '双床房', '家庭亲子', 79, 4.382026634673881, 0, 0.0, 2, 1.0986122886681098, 8, '["公共设施", "周边配套", "前台服务"]'::jsonb, '公共设施', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '酒店非常有特色，味道也很好闻，宝格丽的洗护用品，4楼还有酒店博物馆，周边吃的也很', '酒店非常有特色，味道也很好闻，宝格丽的洗护用品，4楼还有酒店博物馆，周边吃的也很多，户外泳池也很干净，适合商务，亲子游，前台的Doris也很nice，态度很好', '2023-06-20', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f7ee3c98b0941765cf1', '早在携程上买的套餐圈，有幸来此体验一下白金五星级酒店的感受，太值了，酒店装饰处处显示着奢华高端，中西合璧，好养眼哦！服务更是一流，进店就有迎宾小姐引路，虽然前台非常忙碌，还很耐心细致，前台的美女小梁为了我们的套餐落实，几经周折才完事，在此特别感谢！', '["https://dimg04.c-ctrip.com/images/0232412000cp32cxp3E45_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000cp30nl695CC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000cp38kghF5D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000cp378ko2984_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000cp3azslB041_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000cp319zi56A0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000cp3b59049A9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000cp35qkm2E3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000cp2xezfD6FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-08', '红棉双床套房', '套房', '其他', 124, 4.8283137373023015, 0, 0.0, 173, 5.159055299214529, 8, '["性价比", "整体满意度", "前台服务"]'::jsonb, '性价比', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '早在携程上买的套餐圈，有幸来此体验一下白金五星级酒店的感受，太值了，酒店装饰处处', '早在携程上买的套餐圈，有幸来此体验一下白金五星级酒店的感受，太值了，酒店装饰处处显示着奢华高端，中西合璧，好养眼哦！服务更是一流，进店就有迎宾小姐引路，虽然前台非常忙碌，还很耐心细致，前台的美女小梁为了我们的套餐落实，几经周折才完事，在此特别感谢！', '2023-12-08', 5, '性价比');
