INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f95e3c98b0941765d01', '不愧是花园酒店 景色怡人 美不胜收 酒店环境服务都很好 可惜美中不足泳池在维修', '["https://dimg04.c-ctrip.com/images/0234d12000bygma5dD7C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000byga2ch471F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000bygfbm3D65B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000bygkzzf1A50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 39, 3.688879454113936, 0, 0.0, 18, 2.9444389791664403, 6, '["景观/朝向", "整体满意度", "公共设施"]'::jsonb, '景观/朝向', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '不愧是花园酒店 景色怡人 美不胜收 酒店环境服务都很好 可惜美中不足泳池在维修', '不愧是花园酒店 景色怡人 美不胜收 酒店环境服务都很好 可惜美中不足泳池在维修', '2023-08-20', 4, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f95e3c98b0941765d02', '这次广州之行花园酒店给了很大惊喜啊！如果说喜欢广州十分，那么花园酒店占了此行一大半，吃住都ok，首先夸一夸办入住的小哥Tony（应该是他吧）很专业，办理业务快速且介绍的很周到啦，因为我是岭客汇金会会员但第一次住花园，所以Tony给升级了双人套房，且临母亲节Tony及时送上康乃馨。整个花园酒店的装修气氛都非常喜欢，环境优雅，早餐是瀑布餐厅和二楼荔湾艇水准都不错！离开时候Kristy和Ellie还送了伴手礼哈，下次来广州一定还住花园啦！', '["https://dimg04.c-ctrip.com/images/0232112000b8odlvaC5B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000b8opzw94741_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000b8osvgpAE62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000b8okalqF904_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000b8owe8bB554_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000b8oex8aB933_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000b8oqzpa44F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000b8otte1885D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-17', '花园双床房', '双床房', '家庭亲子', 218, 5.389071729816501, 0, 0.0, 13, 2.6390573296152584, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '这次广州之行花园酒店给了很大惊喜啊！如果说喜欢广州十分，那么花园酒店占了此行一大', '这次广州之行花园酒店给了很大惊喜啊！如果说喜欢广州十分，那么花园酒店占了此行一大半，吃住都ok，首先夸一夸办入住的小哥Tony（应该是他吧）很专业，办理业务快速且介绍的很周到啦，因为我是岭客汇金会会员但第一次住花园，所以Tony给升级了双人套房，且临母亲节Tony及时送上康乃馨。整个花园酒店的装修气氛都非常喜欢，环境优雅，早餐是瀑布餐厅和二楼荔湾艇水准都不错！离开时候Kristy和Ellie还送了伴手礼哈，下次来广州一定还住花园啦！', '2023-05-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f95e3c98b0941765d03', '酒店的硬件设施齐全，毕竟是五星级酒店，前台服务人员Viria服务态度好，礼貌好客，我们带着小孩子差不多凌晨的时候入住，还很贴心的询问我们需不需要帮忙！酒店的后花园有两个人工瀑布，喜欢拍照的姐妹可以去看看，唯一不足就是热水水温不稳定，时冷时热，有点糟心！总体体验感ok', '["https://dimg04.c-ctrip.com/images/0235u12000b76nvlm8B96_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-05-11', '花园双床房', '双床房', '家庭亲子', 133, 4.897839799950911, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店的硬件设施齐全，毕竟是五星级酒店，前台服务人员Viria服务态度好，礼貌好客', '酒店的硬件设施齐全，毕竟是五星级酒店，前台服务人员Viria服务态度好，礼貌好客，我们带着小孩子差不多凌晨的时候入住，还很贴心的询问我们需不需要帮忙！酒店的后花园有两个人工瀑布，喜欢拍照的姐妹可以去看看，唯一不足就是热水水温不稳定，时冷时热，有点糟心！总体体验感ok', '2023-05-11', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f95e3c98b0941765d04', '房间肯定不好，服务生倒是有求必应，很好，凌晨两点维修水管，切割机声音巨响，一晚上都没睡好，凌晨两点换房间睡，这你受得了？', '["https://dimg04.c-ctrip.com/images/0234k12000bmwj2y5036C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000bmwrczl17E1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-07-12', '花园双床房', '双床房', '商务出差', 60, 4.110873864173311, 0, 0.0, 13, 2.6390573296152584, 8, '["安静程度", "客房服务", "整体满意度"]'::jsonb, '安静程度', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间肯定不好，服务生倒是有求必应，很好，凌晨两点维修水管，切割机声音巨响，一晚上', '房间肯定不好，服务生倒是有求必应，很好，凌晨两点维修水管，切割机声音巨响，一晚上都没睡好，凌晨两点换房间睡，这你受得了？', '2023-07-12', 3, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027f95e3c98b0941765d05', '大堂经理bobo非常热情周到，服务细心。客房服务响应都很及时，特别是看到我客人比较多，经常在客厅喝茶谈事，主动送进来一箱矿泉水，感觉很贴心。', '["https://dimg04.c-ctrip.com/images/0235b12000c3fcv3421E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000c3fnlrz374D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-09', '花园大床房', '大床房', '商务出差', 70, 4.262679877041316, 0, 0.0, 14, 2.70805020110221, 8, '["前台服务", "客房服务"]'::jsonb, '前台服务', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '大堂经理bobo非常热情周到，服务细心。客房服务响应都很及时，特别是看到我客人比', '大堂经理bobo非常热情周到，服务细心。客房服务响应都很及时，特别是看到我客人比较多，经常在客厅喝茶谈事，主动送进来一箱矿泉水，感觉很贴心。', '2023-09-09', 5, '前台服务');
