INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fc2e3c98b0941765d28', '第一次假期出游选择花园酒店，确实很惊艳，小朋友很喜欢。因行程比较赶，都来不及细细品味这家老牌酒店，荔湾亭的一元一碗豆腐花让人印象深刻。前台阿KEN服务很友好，让人如沐春风，下次还会来。', '["https://dimg04.c-ctrip.com/images/0232312000cbqh7emF3B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000cbqlihv0C86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000cbqifcsE35E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-04', '粤韵双床套房', '套房', '家庭亲子', 92, 4.532599493153256, 0, 0.0, 14, 2.70805020110221, 7, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '第一次假期出游选择花园酒店，确实很惊艳，小朋友很喜欢。因行程比较赶，都来不及细细', '第一次假期出游选择花园酒店，确实很惊艳，小朋友很喜欢。因行程比较赶，都来不及细细品味这家老牌酒店，荔湾亭的一元一碗豆腐花让人印象深刻。前台阿KEN服务很友好，让人如沐春风，下次还会来。', '2023-10-04', 5, '前台服务');
