INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fcee3c98b0941765d33', '酒店太让人震感惊艳了！打假期间，服务不打折，热情周到主动！并且还为我们房间升级为套房！服务特别贴心！早餐很丰富，各种风味品类，餐厅都有三个，随便任由自己选择！广州花园酒店代表着广州经济的飞速发展与经济地位！花园酒店不仅有沉淀，地理位置还非常方便，出门就是地铁，无论到那里景区都是最方便的选择！', '["https://dimg04.c-ctrip.com/images/0230m12000b4lf31p1A52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000b4lq19cE256_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000b4lnm982E1D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000b4ltzv149F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-01', '花园双床房', '双床房', '家庭亲子', 146, 4.990432586778736, 0, 0.0, 186, 5.231108616854587, 9, '["前台服务", "餐饮设施", "交通便利性"]'::jsonb, '前台服务', '餐饮设施', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店太让人震感惊艳了！打假期间，服务不打折，热情周到主动！并且还为我们房间升级为', '酒店太让人震感惊艳了！打假期间，服务不打折，热情周到主动！并且还为我们房间升级为套房！服务特别贴心！早餐很丰富，各种风味品类，餐厅都有三个，随便任由自己选择！广州花园酒店代表着广州经济的飞速发展与经济地位！花园酒店不仅有沉淀，地理位置还非常方便，出门就是地铁，无论到那里景区都是最方便的选择！', '2023-05-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fcee3c98b0941765d34', '半夜五点，突然被暴力的踢门声吓醒，还一脸蒙蔽，然后还继续踢，吓**，老公通过猫眼看是有个外国人在踢对面的房门，还一直在门口吵，我还以为是踢我们的房门赶紧用座机打电话客服中心，居然没人听。后来用手机搜电话打通让人上来处理，**的吓**还带着孩子呢！', '["https://dimg04.c-ctrip.com/images/0235t12000ax261oyC33E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-04-12', '花园大床房', '大床房', '家庭亲子', 123, 4.820281565605037, 3, 1.3862943611198906, 2, 1.0986122886681098, 8, '["安静程度", "前台服务"]'::jsonb, '安静程度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '半夜五点，突然被暴力的踢门声吓醒，还一脸蒙蔽，然后还继续踢，吓**，老公通过猫眼', '半夜五点，突然被暴力的踢门声吓醒，还一脸蒙蔽，然后还继续踢，吓**，老公通过猫眼看是有个外国人在踢对面的房门，还一直在门口吵，我还以为是踢我们的房门赶紧用座机打电话客服中心，居然没人听。后来用手机搜电话打通让人上来处理，**的吓**还带着孩子呢！', '2023-04-12', 3, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fcee3c98b0941765d35', '金玉其外 败絮其中。4.6的分都高了。
真诚的建议所有想来体验五星白金酒店的旅客不要入住花园酒店。来大厅，四楼博物馆（免费的对外开放登记就能进入），还有瀑布后花园（入口在瀑布餐厅和前台中间在一个酒柜那里对外开放不用刷卡）打卡即可。 餐厅也都是对外开放的。
真心不用花一千多块钱大老远跑来住又破又脏的房间。
1 酒店未提前告知最近有大面积施工??，酒店后面全部是工地，每天早上7点半准时开工晚上8点半回来噪声还非常大。（详见两个视频第一个工地??第二个是在床上录的）想象一下这个噪音。心脏脆弱的人会得心脏病的声音非常大。
2 刚入住就发现房间地板上有很多头发，赶紧联系客房部。大概十分钟后服务生来吸了地。卫生一塌糊涂有被浴室排水槽里的头发和棉签恶心??烧水壶上还有白乎乎的水垢可以扣下来的那种。桌子上也有不明白色粉末。
3 强烈怀疑说是装修过了的，有污渍的音响，老化的浴室，破旧的天花板，破了用透明胶带粘住的桌面，有污点的沙发，和看上去快要退休的椅子??。
4 头一回碰见在入住时就被要求离店打五星好评？！！！我房间都没进呢就要我打五星好评？！！！目的性太强，入住时我说小羊很可爱想买一只前台说离店时可以送我一只，但是！必须离店时出示带有她名字的五星好评！！！才能送我！！入住时说这些令人很不舒服。 （就这水准五星好评不可能的）最后离店时前台说小羊没有了送积木（从来就没打算要酒店送小羊）。不用了真的太糟糕了。
5 找了经理投诉态度很好，经理邀请下次入住时升级房间。婉拒了，没有下次了。
6 可以考虑用本地品牌的茶叶，毕竟主打岭南风用英国????茶不伦不类。外宾多更要让人家尝尝本地茶叶啊？！自己说的要打造民族品牌奢华酒店。
后悔没住凯宾斯基了差不多的价格人家还新还没施工也有高楼层景色，走到花园五分钟打个卡多好。', '["https://dimg04.c-ctrip.com/images/0200u12000arnzgtm6D66_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0206s12000arnzmwg4E1C_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0235j12000arnrhyl79B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000arntmxxD29F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000arnknrg4751_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000arnmps874B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000arnjy5qEC79_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000arnsb661A9A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000arnmnq40107_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000arnqcle8E28_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000arnqloi5D6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-03-13', '城央绿意大床房', '大床房', '独自旅行', 764, 6.639875833826536, 22, 3.1354942159291497, 134, 4.90527477843843, 9, '["房间设施", "卫生状况", "安静程度"]'::jsonb, '房间设施', '卫生状况', '安静程度', '未知酒店', '未知地点', '匿名', '金玉其外 败絮其中。4.6的分都高了。', '金玉其外 败絮其中。4.6的分都高了。
真诚的建议所有想来体验五星白金酒店的旅客不要入住花园酒店。来大厅，四楼博物馆（免费的对外开放登记就能进入），还有瀑布后花园（入口在瀑布餐厅和前台中间在一个酒柜那里对外开放不用刷卡）打卡即可。 餐厅也都是对外开放的。
真心不用花一千多块钱大老远跑来住又破又脏的房间。
1 酒店未提前告知最近有大面积施工??，酒店后面全部是工地，每天早上7点半准时开工晚上8点半回来噪声还非常大。（详见两个视频第一个工地??第二个是在床上录的）想象一下这个噪音。心脏脆弱的人会得心脏病的声音非常大。
2 刚入住就发现房间地板上有很多头发，赶紧联系客房部。大概十分钟后服务生来吸了地。卫生一塌糊涂有被浴室排水槽里的头发和棉签恶心??烧水壶上还有白乎乎的水垢可以扣下来的那种。桌子上也有不明白色粉末。
3 强烈怀疑说是装修过了的，有污渍的音响，老化的浴室，破旧的天花板，破了用透明胶带粘住的桌面，有污点的沙发，和看上去快要退休的椅子??。
4 头一回碰见在入住时就被要求离店打五星好评？！！！我房间都没进呢就要我打五星好评？！！！目的性太强，入住时我说小羊很可爱想买一只前台说离店时可以送我一只，但是！必须离店时出示带有她名字的五星好评！！！才能送我！！入住时说这些令人很不舒服。 （就这水准五星好评不可能的）最后离店时前台说小羊没有了送积木（从来就没打算要酒店送小羊）。不用了真的太糟糕了。
5 找了经理投诉态度很好，经理邀请下次入住时升级房间。婉拒了，没有下次了。
6 可以考虑用本地品牌的茶叶，毕竟主打岭南风用英国????茶不伦不类。外宾多更要让人家尝尝本地茶叶啊？！自己说的要打造民族品牌奢华酒店。
后悔没住凯宾斯基了差不多的价格人家还新还没施工也有高楼层景色，走到花园五分钟打个卡多好。', '2023-03-13', 2, '房间设施');
