INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fcee3c98b0941765d37', '前台接待亲切友好，住宿环境舒适，房间干净卫生，酒店自助早餐丰富，交通便利配套足，性价比很高，下次再入住，值得推荐！', '["https://dimg04.c-ctrip.com/images/0236a2215fddosbm8E3D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023492215fddosbm9C419_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u2224vgquvahs4ECC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b2224vgquvi7k1C44_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-17', '花园大床房', '大床房', '独自旅行', 57, 4.060443010546419, 0, 0.0, 15, 2.772588722239781, 7, '["整体满意度", "前台服务", "性价比"]'::jsonb, '整体满意度', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '前台接待亲切友好，住宿环境舒适，房间干净卫生，酒店自助早餐丰富，交通便利配套足，', '前台接待亲切友好，住宿环境舒适，房间干净卫生，酒店自助早餐丰富，交通便利配套足，性价比很高，下次再入住，值得推荐！', '2023-06-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fcee3c98b0941765d38', '广州花园酒店的发展，见证了中国改革开放后的文化，经济，政治变化，成立于1984年，由邓小平题字，是改革开放后第一家引进外资的酒店，酒店大堂简直是太美了，背景墙给我们带入了曹雪芹笔下的《红楼梦》场景和水乡风貌，里面有一家博物馆，让我们了解到很多酒店业的历史和文化，后花园里边非常精彩只入住了两天，感觉恋恋不舍，所有地方都太喜欢了！我认为是到广州住酒店的首选！', '["https://dimg04.c-ctrip.com/images/0200c12000awgtdm1293C_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0201912000awgtdz4FFDD_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0204w12000awgte0p2243_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0234012000aw4ytzrA66E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000aw4waj178CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000aw4to7eC242_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000aw4wls60BC0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000awgs08kF03A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000aw4ounj9F85_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000awg4n8x3557_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-10', '花园大床房', '大床房', '情侣出游', 178, 5.187385805840755, 0, 0.0, 67, 4.219507705176107, 9, '["整体满意度", "公共设施"]'::jsonb, '整体满意度', '公共设施', NULL, '未知酒店', '未知地点', '匿名', '广州花园酒店的发展，见证了中国改革开放后的文化，经济，政治变化，成立于1984年', '广州花园酒店的发展，见证了中国改革开放后的文化，经济，政治变化，成立于1984年，由邓小平题字，是改革开放后第一家引进外资的酒店，酒店大堂简直是太美了，背景墙给我们带入了曹雪芹笔下的《红楼梦》场景和水乡风貌，里面有一家博物馆，让我们了解到很多酒店业的历史和文化，后花园里边非常精彩只入住了两天，感觉恋恋不舍，所有地方都太喜欢了！我认为是到广州住酒店的首选！', '2023-04-10', 5, '整体满意度');
