INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d3c', '这是一家充满历史，环境优美，体验舒适的酒店，性价比很高！花园酒店实至名归，仿佛置身一座美丽的后花园中。酒店除了房间面积小了点，其他都很好。餐厅泳池健身房也都不错，桃园餐厅稍微有点贵。附近有很多老字号，点都德、陶陶居都不错，尤其是点都德好吃不贵！', '["https://dimg04.c-ctrip.com/images/0236y12000ayyog6qB1A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000ayyrd1f0D39_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000ayygth3E88A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000ayxvhyfA2C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000ayyluqj0ED1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000ayyut5x4C68_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000ayysfld8308_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-17', '花园大床房', '大床房', '家庭亲子', 122, 4.812184355372417, 0, 0.0, 15, 2.772588722239781, 8, '["整体满意度", "性价比", "周边配套"]'::jsonb, '整体满意度', '性价比', '周边配套', '未知酒店', '未知地点', '匿名', '这是一家充满历史，环境优美，体验舒适的酒店，性价比很高！花园酒店实至名归，仿佛置', '这是一家充满历史，环境优美，体验舒适的酒店，性价比很高！花园酒店实至名归，仿佛置身一座美丽的后花园中。酒店除了房间面积小了点，其他都很好。餐厅泳池健身房也都不错，桃园餐厅稍微有点贵。附近有很多老字号，点都德、陶陶居都不错，尤其是点都德好吃不贵！', '2023-04-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d3d', '非常有历史韵味的酒店，大堂很美，但是房间内部设施偏老旧。位置在老城区内算比较方便的，离地铁近，旁边也有商场还有几家比较有名的粤菜馆。整体服务不错，因带孩子还给帮忙延迟退房了。但是人真多，办理入住，吃早饭 都要排队。', '["https://dimg04.c-ctrip.com/images/0230g12000ayg9jbl5DCA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-04-15', '红棉大床套房', '套房', '家庭亲子', 107, 4.68213122712422, 0, 0.0, 2, 1.0986122886681098, 8, '["房间设施", "交通便利性", "周边配套"]'::jsonb, '房间设施', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '非常有历史韵味的酒店，大堂很美，但是房间内部设施偏老旧。位置在老城区内算比较方便', '非常有历史韵味的酒店，大堂很美，但是房间内部设施偏老旧。位置在老城区内算比较方便的，离地铁近，旁边也有商场还有几家比较有名的粤菜馆。整体服务不错，因带孩子还给帮忙延迟退房了。但是人真多，办理入住，吃早饭 都要排队。', '2023-04-15', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d3e', '我们住的楼层外面在修路，没什么好看的，但是没有很吵，对我们没什么影响，入住之前就已经提醒了，市政工程也能理解，办理入住的时候给小朋友提供了小饼干，服务很好，后花园很美，自己带的面包，小朋友去喂了鱼，装修风格很有岭南特色，还特意去参观了四楼的酒店博物馆，小朋友还很喜欢这里，下次还会选择入住这里。', '["https://dimg04.c-ctrip.com/images/0233q12000aw2d4uwBFF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-04-09', '城央绿意双床房', '双床房', '家庭亲子', 147, 4.997212273764115, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '我们住的楼层外面在修路，没什么好看的，但是没有很吵，对我们没什么影响，入住之前就', '我们住的楼层外面在修路，没什么好看的，但是没有很吵，对我们没什么影响，入住之前就已经提醒了，市政工程也能理解，办理入住的时候给小朋友提供了小饼干，服务很好，后花园很美，自己带的面包，小朋友去喂了鱼，装修风格很有岭南特色，还特意去参观了四楼的酒店博物馆，小朋友还很喜欢这里，下次还会选择入住这里。', '2023-04-09', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d3f', '环境不错，地铁施工有点吵，其它都不错', '["https://dimg04.c-ctrip.com/images/0230e12000c0dxpwv29BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000c0dxls94778_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000c0dxiy6CE19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000c0dxno92A5A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000c0dxnoc8BA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-26', '花园大床房', '大床房', '家庭亲子', 18, 2.9444389791664403, 0, 0.0, 2, 1.0986122886681098, 4, '["安静程度", "整体满意度"]'::jsonb, '安静程度', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '环境不错，地铁施工有点吵，其它都不错', '环境不错，地铁施工有点吵，其它都不错', '2023-08-26', 5, '安静程度');
