INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d43', '卫生怎能这么的差呢？', '["https://dimg04.c-ctrip.com/images/0232a12000c3kf786D4C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000c3kead000FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000c3kj270AEFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000c3kd5c82717_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.0, 2, '2023-09-09', '花园双床房', '双床房', '独自旅行', 10, 2.3978952727983707, 0, 0.0, 9, 2.302585092994046, 3, '["卫生状况"]'::jsonb, '卫生状况', NULL, NULL, '未知酒店', '未知地点', '匿名', '卫生怎能这么的差呢？', '卫生怎能这么的差呢？', '2023-09-09', 2, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d44', '一点都不值800+的价格 其他品牌四星酒店更便宜 这是更优 花园就靠着这个牌子赚足了人气 但是败絮其中
这个房间多说也就价值400-500 纯纯大冤种 因为太不满意想要提前离店 退换未住部分 但是经销商和酒店踢皮球 只能继续住
环境：除了房间家具设施 真的很富丽堂皇 公共区域干净整洁 气味香香的 电梯数量足 冷气足
服务：从进门开始 门口迎宾 大堂服务 客房服务 礼宾服务工作人员服务都很好 态度很友好 满足需求 很满意
设施：水压很大 洗澡舒服 & 床够大够软 睡觉很舒服
但是页面上写的2019年装修 但是地板家具很陈旧 椅子皮很老了 真的该换了上面有明显污渍
电子秤没有电的 换了新的 后又因外部道路施工噪音问题换了房间 新的房间电子秤依然没电……
卫生：桌面和椅子用纯水湿巾擦拭能明显变黄 擦拭完后再擦无变黄 说明平时清理不够
换新的房间床上状况没有第一间好 床面看起来像是没有更换 两张床被子掀开都能发现不止一根毛发', '["https://dimg04.c-ctrip.com/images/0235q12000auxqces35FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000auxxw1q0892_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000auxvz9m5EA8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000auxu58e51A5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000auy3mt3B505_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000auy4c66DE30_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000auy1ohaF396_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-04-05', '花园双床房', '双床房', '朋友出游', 418, 6.037870919922137, 1, 0.6931471805599453, 2, 1.0986122886681098, 9, '["性价比", "房间设施", "卫生状况"]'::jsonb, '性价比', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '一点都不值800+的价格 其他品牌四星酒店更便宜 这是更优 花园就靠着这个牌子赚', '一点都不值800+的价格 其他品牌四星酒店更便宜 这是更优 花园就靠着这个牌子赚足了人气 但是败絮其中
这个房间多说也就价值400-500 纯纯大冤种 因为太不满意想要提前离店 退换未住部分 但是经销商和酒店踢皮球 只能继续住
环境：除了房间家具设施 真的很富丽堂皇 公共区域干净整洁 气味香香的 电梯数量足 冷气足
服务：从进门开始 门口迎宾 大堂服务 客房服务 礼宾服务工作人员服务都很好 态度很友好 满足需求 很满意
设施：水压很大 洗澡舒服 & 床够大够软 睡觉很舒服
但是页面上写的2019年装修 但是地板家具很陈旧 椅子皮很老了 真的该换了上面有明显污渍
电子秤没有电的 换了新的 后又因外部道路施工噪音问题换了房间 新的房间电子秤依然没电……
卫生：桌面和椅子用纯水湿巾擦拭能明显变黄 擦拭完后再擦无变黄 说明平时清理不够
换新的房间床上状况没有第一间好 床面看起来像是没有更换 两张床被子掀开都能发现不止一根毛发', '2023-04-05', 3, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fdfe3c98b0941765d45', '原本订了威斯汀，因为有儿童设施和儿童装饰，但是自己内心还是喜欢感受美食文化和有历史沉淀的花园酒店！从桂林过来的火车上取消了威斯汀，下单了花园酒店。之前看评论说有市政工程很吵，入住当天Joe帮我排了远一点的房间，升级了房间，给姐姐也加了床（小朋友不要跟我和弟弟睡），特别感谢！除了门口迎宾的不太满意外，其他的工作人员都还是满意的！晚上荔湾亭吃饭也帮忙点菜准备宝宝餐具，不算热情但是还是周到的！第二天起来立马续房！老牌五星很有味道！', '["https://dimg04.c-ctrip.com/images/0235j12000bk073k45955_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000bk0brxkE9C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000bk0876k6523_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000bk06o4m1D2A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000bk0bmzf9FC8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000bk073k67B9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000bk0miru3553_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000bk07j9mD90C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000bk0k4c14EF9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-02', '红棉大床套房', '套房', '家庭亲子', 214, 5.3706380281276624, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '原本订了威斯汀，因为有儿童设施和儿童装饰，但是自己内心还是喜欢感受美食文化和有历', '原本订了威斯汀，因为有儿童设施和儿童装饰，但是自己内心还是喜欢感受美食文化和有历史沉淀的花园酒店！从桂林过来的火车上取消了威斯汀，下单了花园酒店。之前看评论说有市政工程很吵，入住当天Joe帮我排了远一点的房间，升级了房间，给姐姐也加了床（小朋友不要跟我和弟弟睡），特别感谢！除了门口迎宾的不太满意外，其他的工作人员都还是满意的！晚上荔湾亭吃饭也帮忙点菜准备宝宝餐具，不算热情但是还是周到的！第二天起来立马续房！老牌五星很有味道！', '2023-07-02', 5, '前台服务');
