INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fe9e3c98b0941765d49', '足足十年没有去过花园酒店了，这次去没有失望，感慨良多，酒店整体装饰保留着原来的风格，也增加了一些新的元素，比如前台变成了一个个独立办理入住的柜台，很多改变都很好，房间也翻新过，前台Semmy 的服务非常好，包括餐厅和大堂吧的服务都很好。我自己做酒店行业，说实话，花园酒店的配套是广州酒店行业里面，我认为没有其他酒店能超越。另外能保持这么好的服务水平，真的超出我的期望。', '["https://dimg04.c-ctrip.com/images/0232g12000auy2tyj7A31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000auxt1h9B6B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-05', '花园大床房', '大床房', '家庭亲子', 184, 5.220355825078324, 0, 0.0, 4, 1.6094379124341005, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '足足十年没有去过花园酒店了，这次去没有失望，感慨良多，酒店整体装饰保留着原来的风', '足足十年没有去过花园酒店了，这次去没有失望，感慨良多，酒店整体装饰保留着原来的风格，也增加了一些新的元素，比如前台变成了一个个独立办理入住的柜台，很多改变都很好，房间也翻新过，前台Semmy 的服务非常好，包括餐厅和大堂吧的服务都很好。我自己做酒店行业，说实话，花园酒店的配套是广州酒店行业里面，我认为没有其他酒店能超越。另外能保持这么好的服务水平，真的超出我的期望。', '2023-04-05', 5, '整体满意度');
