INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027fe9e3c98b0941765d4b', '来了很多次了 一如既往地喜欢 吃喝玩乐都在酒店里了 三楼参观了广州花园自己的博物馆，吃了一楼日料，二楼的正宗广式小吃，都是大众点评上不错的餐厅。
