INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ff5e3c98b0941765d52', '广州的花园酒店、白天鹅宾馆、白云宾馆一直是我这个五十多岁人心中的白月光，此次去广州旅游选择了花园酒店，原因有三：一、酒店门口即是地铁站，去景点、去机场在地面交通拥堵的情况下都能坐地铁到达；二、酒店内有博物馆，自带博物馆的酒店国内真的不多，闲暇之余参观一下，增长些知识也是件好事；三：酒店地处繁华地段，附近吃、喝、玩、乐非常方便。
下了出租，走进大堂的一刻，?一幅硕大的壁画映入眼帘，用金璧辉??来形容此画一点也不夸张，据说此画用了二公斤黄金-奢华！预定了二间房，因一间房仍在打扫中，前台竟然很客气地把房间升了级，升到了套房，而且，还贴心地提醒了一下：窗外正在进行地铁施工，有可能影响睡眠。第二天退房人又较多，在排队时有个女主管上来询问，当得知我们未使用房内任何物品后，就马上收了房卡退了房。从入住到退房，花园人的服务态度一流，若以后再来广州，花园将是我不二之选，还会再入住。谢谢！', '["https://dimg04.c-ctrip.com/images/0236z12000aziqdgiF129_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000azil3jhFB2B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000aziw1ec6764_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000azj4y4sFD01_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000azj1yyj0C2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000aziyi4vA2E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-18', '花园大床房', '大床房', '家庭亲子', 390, 5.968707559985366, 0, 0.0, 6, 1.9459101490553128, 9, '["交通便利性", "前台服务", "退房/入住效率"]'::jsonb, '交通便利性', '前台服务', '退房/入住效率', '未知酒店', '未知地点', '匿名', '广州的花园酒店、白天鹅宾馆、白云宾馆一直是我这个五十多岁人心中的白月光，此次去广', '广州的花园酒店、白天鹅宾馆、白云宾馆一直是我这个五十多岁人心中的白月光，此次去广州旅游选择了花园酒店，原因有三：一、酒店门口即是地铁站，去景点、去机场在地面交通拥堵的情况下都能坐地铁到达；二、酒店内有博物馆，自带博物馆的酒店国内真的不多，闲暇之余参观一下，增长些知识也是件好事；三：酒店地处繁华地段，附近吃、喝、玩、乐非常方便。
下了出租，走进大堂的一刻，?一幅硕大的壁画映入眼帘，用金璧辉??来形容此画一点也不夸张，据说此画用了二公斤黄金-奢华！预定了二间房，因一间房仍在打扫中，前台竟然很客气地把房间升了级，升到了套房，而且，还贴心地提醒了一下：窗外正在进行地铁施工，有可能影响睡眠。第二天退房人又较多，在排队时有个女主管上来询问，当得知我们未使用房内任何物品后，就马上收了房卡退了房。从入住到退房，花园人的服务态度一流，若以后再来广州，花园将是我不二之选，还会再入住。谢谢！', '2023-04-18', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ff5e3c98b0941765d53', '行政酒廊很好，', '["https://dimg04.c-ctrip.com/images/0233z12000c3qi2qdB937_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '花园双床房', '双床房', '家庭亲子', 7, 2.079441541679836, 0, 0.0, 2, 1.0986122886681098, 3, '["餐饮设施"]'::jsonb, '餐饮设施', NULL, NULL, '未知酒店', '未知地点', '匿名', '行政酒廊很好，', '行政酒廊很好，', '2023-09-10', 5, '餐饮设施');
