INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ff5e3c98b0941765d55', '赶上活动住的红棉双床房，各方面环境让人感觉宾至如归，健身房，游泳池一应俱全，四楼的酒店博物馆亦是令人大开眼界，了解到花园酒店和整个行业的前世今生。前台“洪小姐”还热情的升级了房型，耐心解答了提出的问题，并且送了入住前点心，“洪小姐”大方得体，服务周到，简直就是花园酒店的一个缩影，总之这是一次非常令人满意的体验。', '["https://dimg04.c-ctrip.com/images/0231t12000c4rcnn1969D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000c4rco2s5D2C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000c4rcmss8D69_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000c4rcnc261B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-14', '红棉双床套房', '套房', '朋友出游', 156, 5.056245805348308, 0, 0.0, 1, 0.6931471805599453, 9, '["公共设施", "前台服务", "整体满意度"]'::jsonb, '公共设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '赶上活动住的红棉双床房，各方面环境让人感觉宾至如归，健身房，游泳池一应俱全，四楼', '赶上活动住的红棉双床房，各方面环境让人感觉宾至如归，健身房，游泳池一应俱全，四楼的酒店博物馆亦是令人大开眼界，了解到花园酒店和整个行业的前世今生。前台“洪小姐”还热情的升级了房型，耐心解答了提出的问题，并且送了入住前点心，“洪小姐”大方得体，服务周到，简直就是花园酒店的一个缩影，总之这是一次非常令人满意的体验。', '2023-09-14', 5, '公共设施');
