INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802800be3c98b0941765d65', '很有特色的酒店，一楼有点像购物中心，花园比我想的大，酒店里面还有博物馆可以看看，服务也很友善，正赶上中秋节大堂的rain姐姐还送了一盒月饼??，感谢??????', '["https://dimg04.c-ctrip.com/images/0235012000ca4azr6B060_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000ca4ad5p7034_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000ca46w5eCCE5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000ca488scA12E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000ca4c5ni31B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000ca4j3a3BADC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-29', '花园双床房', '双床房', '朋友出游', 80, 4.394449154672439, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '很有特色的酒店，一楼有点像购物中心，花园比我想的大，酒店里面还有博物馆可以看看，', '很有特色的酒店，一楼有点像购物中心，花园比我想的大，酒店里面还有博物馆可以看看，服务也很友善，正赶上中秋节大堂的rain姐姐还送了一盒月饼??，感谢??????', '2023-09-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802800be3c98b0941765d66', '中秋假期订了广州老牌的花园酒店，在一众涨价的各大五星酒店面前性价比很高。红棉大床房很大，有客厅和卧室有效隔开，内部装潢历久弥新，只有历史的厚重感没有陈旧过时的感觉。服务也很好，特别是Tia小姐姐很贴心的送了月饼，好评！下次还会推荐亲朋好友来住～', '["https://dimg04.c-ctrip.com/images/0231i12000fmct7yp36D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000fmcjc66060E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000fmcz9hx0872_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-18', '红棉大床套房', '套房', '情侣出游', 122, 4.812184355372417, 0, 0.0, 6, 1.9459101490553128, 9, '["性价比", "房间设施", "整体满意度"]'::jsonb, '性价比', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '中秋假期订了广州老牌的花园酒店，在一众涨价的各大五星酒店面前性价比很高。红棉大床', '中秋假期订了广州老牌的花园酒店，在一众涨价的各大五星酒店面前性价比很高。红棉大床房很大，有客厅和卧室有效隔开，内部装潢历久弥新，只有历史的厚重感没有陈旧过时的感觉。服务也很好，特别是Tia小姐姐很贴心的送了月饼，好评！下次还会推荐亲朋好友来住～', '2024-09-18', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802800be3c98b0941765d67', '入住时前台Billy的接待自信大方，不仅赠送了小礼物和升级了房型，还介绍了酒店各个区域及预约方式。
因酒店毕竟时间太长了房间设备比较陈旧可以理解，但也都是好用的。来住这家酒店最主要的目的是去博物馆，对酒店文化一直很感兴趣，博物馆的确各个细节也做的很好，希望花园酒店可以把博物馆的内容出一套书，对酒店爱好者来说会很有意义。
一楼瀑布餐厅的服务也很贴心，体验感很好。
唯一希望改善的是客房餐饮部的出品，点了白葡萄酒但送来时既没有冰桶，酒杯虽是冰过的但是上面擦不掉的水渍还是很影响心情，再次送来的干净杯子就不是白酒杯了……', '["https://dimg04.c-ctrip.com/images/0233b12000bbi8poxC5F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000bbi1y6nCA70_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-30', '花园大床房', '大床房', '独自旅行', 258, 5.556828061699537, 0, 0.0, 20, 3.044522437723423, 9, '["前台服务", "餐饮设施", "房间设施"]'::jsonb, '前台服务', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '入住时前台Billy的接待自信大方，不仅赠送了小礼物和升级了房型，还介绍了酒店各', '入住时前台Billy的接待自信大方，不仅赠送了小礼物和升级了房型，还介绍了酒店各个区域及预约方式。
因酒店毕竟时间太长了房间设备比较陈旧可以理解，但也都是好用的。来住这家酒店最主要的目的是去博物馆，对酒店文化一直很感兴趣，博物馆的确各个细节也做的很好，希望花园酒店可以把博物馆的内容出一套书，对酒店爱好者来说会很有意义。
一楼瀑布餐厅的服务也很贴心，体验感很好。
唯一希望改善的是客房餐饮部的出品，点了白葡萄酒但送来时既没有冰桶，酒杯虽是冰过的但是上面擦不掉的水渍还是很影响心情，再次送来的干净杯子就不是白酒杯了……', '2023-05-30', 5, '前台服务');
