INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802800be3c98b0941765d6d', '之前来广州都是首选花园酒店，這次入住真的很失望，住两晚换了三次房间！
定的无烟房被分派了有烟房，一进门就是扑鼻的烟味。和前台反应换到了无烟房，但房间打扫完全不到位，卫生间还留有之前住客的使用痕迹，再次下楼和反应，接待的礼仪小姐姐还是很不错！立即安排换房又做了升级。 
换到了行政套房房间整体都还不错，但一开空调房间的出风口就是一股下水道酸臭味漂出来，可惜当晚没房可换了，只能让阿姨拿了空气清新剂和空气净化器先解决一下。
事后得知据说16层以上才是新装修的，后续要入住的尽量选高楼层的吧！', '["https://dimg04.c-ctrip.com/images/0232912000ayae91q21D2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-04-15', '花园双床房', '双床房', '朋友出游', 245, 5.5053315359323625, 0, 0.0, 10, 2.3978952727983707, 9, '["房间设施", "前台服务", "卫生状况"]'::jsonb, '房间设施', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '之前来广州都是首选花园酒店，這次入住真的很失望，住两晚换了三次房间！', '之前来广州都是首选花园酒店，這次入住真的很失望，住两晚换了三次房间！
定的无烟房被分派了有烟房，一进门就是扑鼻的烟味。和前台反应换到了无烟房，但房间打扫完全不到位，卫生间还留有之前住客的使用痕迹，再次下楼和反应，接待的礼仪小姐姐还是很不错！立即安排换房又做了升级。 
换到了行政套房房间整体都还不错，但一开空调房间的出风口就是一股下水道酸臭味漂出来，可惜当晚没房可换了，只能让阿姨拿了空气清新剂和空气净化器先解决一下。
事后得知据说16层以上才是新装修的，后续要入住的尽量选高楼层的吧！', '2023-04-15', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028017e3c98b0941765d6e', '出行首先广州花园酒店，各方面服务都非常赞无论是前台接待还是客房餐厅都挑不出一丁点毛病，本来是想住一晚办完事就走，前台接待工作人员周到的服务，温暖到了我，毫不犹豫又延住一晚，酒店位置很好对面商城6楼有一家1935年开业的老店特别赞，下次来广州还会选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234412000aqz52jnEAF7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000aqz562r0083_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000aqz562zAC45_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000aqz587084EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000aqz53bs2B85_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000aqz53cm3E7B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000aqz53cxA6DF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000aqz54ua21EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000aqz587vF946_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-07', '花园双床房', '双床房', '商务出差', 129, 4.867534450455582, 0, 0.0, 5, 1.791759469228055, 8, '["前台服务", "整体满意度", "周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套', '未知酒店', '未知地点', '匿名', '出行首先广州花园酒店，各方面服务都非常赞无论是前台接待还是客房餐厅都挑不出一丁点', '出行首先广州花园酒店，各方面服务都非常赞无论是前台接待还是客房餐厅都挑不出一丁点毛病，本来是想住一晚办完事就走，前台接待工作人员周到的服务，温暖到了我，毫不犹豫又延住一晚，酒店位置很好对面商城6楼有一家1935年开业的老店特别赞，下次来广州还会选择花园酒店。', '2023-03-07', 5, '前台服务');
