INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028017e3c98b0941765d72', '酒店交通方便，环境也很棒，服务也好,nice.', '["https://dimg04.c-ctrip.com/images/0235112000bmo8o2t43C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-11', '花园大床房', '大床房', '朋友出游', 23, 3.1780538303479458, 0, 0.0, 4, 1.6094379124341005, 4, '["交通便利性", "整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店交通方便，环境也很棒，服务也好,nice.', '酒店交通方便，环境也很棒，服务也好,nice.', '2023-07-11', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028017e3c98b0941765d73', '第二天还是选择住在花园酒店，因为赶时间就直接把房卡给到迎宾小姐姐续房了！真的满分服务，回来直接到前台拿上饭卡又可以回房间里了，服务还是一如既往的好！
设施：虽然稍微旧了一点，但是品质质感都是满满的赞！床品也还挺舒适的，酒店的水压是我住过这么多酒店以来水压最大的一个，出热水很快且水量很大，洗澡还是很爽的！
晚上去花园逛了逛，小桥流水体现的淋漓尽致，不愧是大师手笔，有瀑布有锦鲤！酒店的酒吧应该也还不错，下次可以去试试', '["https://dimg04.c-ctrip.com/images/0237312000aqt0xknBA63_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000aqt6ju11812_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000aqt5b5f1D60_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000aqt5ln493CC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000aqszkfe20F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000aqt33hj5818_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000aqt6wc5EBF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000aqszloc3C08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-06', '花园大床房', '大床房', '商务出差', 208, 5.342334251964811, 1, 0.6931471805599453, 7, 2.079441541679836, 8, '["前台服务", "房间设施", "公共设施"]'::jsonb, '前台服务', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '第二天还是选择住在花园酒店，因为赶时间就直接把房卡给到迎宾小姐姐续房了！真的满分', '第二天还是选择住在花园酒店，因为赶时间就直接把房卡给到迎宾小姐姐续房了！真的满分服务，回来直接到前台拿上饭卡又可以回房间里了，服务还是一如既往的好！
设施：虽然稍微旧了一点，但是品质质感都是满满的赞！床品也还挺舒适的，酒店的水压是我住过这么多酒店以来水压最大的一个，出热水很快且水量很大，洗澡还是很爽的！
晚上去花园逛了逛，小桥流水体现的淋漓尽致，不愧是大师手笔，有瀑布有锦鲤！酒店的酒吧应该也还不错，下次可以去试试', '2023-03-06', 5, '前台服务');
