INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028022e3c98b0941765d7b', '我们这次入住五晚，对花园酒店的环境服务设施非常满意。 美丽的后花园，优雅的桃园馆和田园浪漫的荔湾亭，丰富多彩的博物馆，房间内的设置也是很贴心。酒店一流的服务人员素质高，很赞。感谢酒店人员的热情接待。', '["https://dimg04.c-ctrip.com/images/0234812000aqigtexC673_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000aqigp4n1421_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000aqijgohF5D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000aqipawyA93F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000aqiiwd001BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000aqikayqAAB0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000aqiifh19A35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000aqifox3A928_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000aqihtqzFD0F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-04', '花园双床房', '双床房', '家庭亲子', 99, 4.605170185988092, 0, 0.0, 82, 4.418840607796598, 8, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '我们这次入住五晚，对花园酒店的环境服务设施非常满意。 美丽的后花园，优雅的桃园馆', '我们这次入住五晚，对花园酒店的环境服务设施非常满意。 美丽的后花园，优雅的桃园馆和田园浪漫的荔湾亭，丰富多彩的博物馆，房间内的设置也是很贴心。酒店一流的服务人员素质高，很赞。感谢酒店人员的热情接待。', '2023-03-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028022e3c98b0941765d7c', '花园酒店有后花园、瀑布很美，大堂气派，门口服务生会主动帮拿行李，酒店历史导览介绍非常好，一楼西式早餐正常。客房设施、家具特别陈旧，有些功能已坏，墙角发霉墙纸发黄，家具破败，完全不像2019年装修，住的无烟楼层二个晚上房间有烟味，跟酒店反映给了一个空气净化器，说对客人在房间内偷偷吸烟酒店也没办法。', '["https://dimg04.c-ctrip.com/images/0232412000aqfjfu1C8D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000aqfhwdz4097_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000aqfk6za228D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-03-03', '城央绿意双床房', '双床房', '朋友出游', 148, 5.003946305945459, 1, 0.6931471805599453, 90, 4.51085950651685, 8, '["房间设施", "卫生状况", "前台服务"]'::jsonb, '房间设施', '卫生状况', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店有后花园、瀑布很美，大堂气派，门口服务生会主动帮拿行李，酒店历史导览介绍', '花园酒店有后花园、瀑布很美，大堂气派，门口服务生会主动帮拿行李，酒店历史导览介绍非常好，一楼西式早餐正常。客房设施、家具特别陈旧，有些功能已坏，墙角发霉墙纸发黄，家具破败，完全不像2019年装修，住的无烟楼层二个晚上房间有烟味，跟酒店反映给了一个空气净化器，说对客人在房间内偷偷吸烟酒店也没办法。', '2023-03-03', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028022e3c98b0941765d7d', '非常不好的一次商务住宿、酒店房间30平米没有窗户一晚要1200元、洗澡站在浴缸里跟厕所共用一个铁门很沉重不方便推来推去。桌子上的插座没电。家具貌似二手市场买来的、前台服务人员衣冠不整头发凌乱、说话也不耐烦。不小心定了个双床房要求更改说大床房要下午五点后才能入住、那就双床房吧要求第二天两点以前退房结果说只能一点钟退房。下次不会再住这个老牌五星级酒店', '["https://dimg04.c-ctrip.com/images/0232v12000apmkidz73A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000apmy6n5F55D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000apn03071945_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000apmu7i46F20_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-02-25', '城央绿意双床房', '双床房', '商务出差', 174, 5.1647859739235145, 3, 1.3862943611198906, 4, 1.6094379124341005, 9, '["房间设施", "前台服务", "价格合理性"]'::jsonb, '房间设施', '前台服务', '价格合理性', '未知酒店', '未知地点', '匿名', '非常不好的一次商务住宿、酒店房间30平米没有窗户一晚要1200元、洗澡站在浴缸里', '非常不好的一次商务住宿、酒店房间30平米没有窗户一晚要1200元、洗澡站在浴缸里跟厕所共用一个铁门很沉重不方便推来推去。桌子上的插座没电。家具貌似二手市场买来的、前台服务人员衣冠不整头发凌乱、说话也不耐烦。不小心定了个双床房要求更改说大床房要下午五点后才能入住、那就双床房吧要求第二天两点以前退房结果说只能一点钟退房。下次不会再住这个老牌五星级酒店', '2023-02-25', 1, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028022e3c98b0941765d7e', '已经很久没有遇到各个方面都没有雷点的酒店了。入住了粤韵客房（金卡升级的），房间很新很舒服。
服务：从前台到礼宾到客房还有餐厅都体验很好，虽然酒店有高达约850间的客房，但是依旧一切都井然有序，对于定位豪华或者奢华的五星级酒店来说并不是简单的事情。
设施：红棉客房往上就蛮大面积了，很舒服。酒店的几家餐厅轮着吃一吃就很舒服了，满意。
