INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802802de3c98b0941765d85', '酒店位置很好，门口就是5号线淘金站，3、8、4号都很方便，酒店不愧是老牌五星酒店，各方面都很不错，房间略小，主要洗漱和卫生间空间比较局促。最令我们印象深刻的是客服服务小李，因为前一天大热天去了长隆，喝了很多水，房间里留了好几个矿泉水空瓶，他不但多给我们补了两瓶水，还手写了一张便条给我们，让人感觉太贴心了。', '["https://dimg04.c-ctrip.com/images/0230c12000f2mzwpa8E45_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000f2mv48t7021_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-10', '花园双床房', '双床房', '家庭亲子', 153, 5.0369526024136295, 0, 0.0, 1, 0.6931471805599453, 9, '["交通便利性", "客房服务", "房间设施"]'::jsonb, '交通便利性', '客房服务', '房间设施', '未知酒店', '未知地点', '匿名', '酒店位置很好，门口就是5号线淘金站，3、8、4号都很方便，酒店不愧是老牌五星酒店', '酒店位置很好，门口就是5号线淘金站，3、8、4号都很方便，酒店不愧是老牌五星酒店，各方面都很不错，房间略小，主要洗漱和卫生间空间比较局促。最令我们印象深刻的是客服服务小李，因为前一天大热天去了长隆，喝了很多水，房间里留了好几个矿泉水空瓶，他不但多给我们补了两瓶水，还手写了一张便条给我们，让人感觉太贴心了。', '2024-08-10', 4, '交通便利性');
