INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d8c', '总体来说，花园酒店的设施和服务都挺好的，床品都很舒服。不过，我们订的时候有送博物馆的票，但是在办入住的时候，前台忘记给我们了，直到check out时候才给，大家自己记得要吧，没有限期，下次再用吧', '["https://dimg04.c-ctrip.com/images/0233m12000aovqpr9617B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-19', '花园大床房', '大床房', '商务出差', 98, 4.59511985013459, 0, 0.0, 5, 1.791759469228055, 6, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '总体来说，花园酒店的设施和服务都挺好的，床品都很舒服。不过，我们订的时候有送博物', '总体来说，花园酒店的设施和服务都挺好的，床品都很舒服。不过，我们订的时候有送博物馆的票，但是在办入住的时候，前台忘记给我们了，直到check out时候才给，大家自己记得要吧，没有限期，下次再用吧', '2023-02-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d8d', '推荐给长隆玩过之后，想留一天的时间给老广州感受岭南文化的朋友。
        酒店在繁华的淘金区，长隆玩过之后打车40分钟左右就到酒店了。因为酒店开业时间早，期望并不高。一进入酒店大堂，我们一家三口就感慨这是此行最满意的酒店了。
         携程白金卡会员订房后可以自动成为岭客汇金卡享受行政酒廊待遇。特别值得体验的是行政酒廊的早餐。推荐户外位置用餐，在瀑布和花园旁享用自助+单点美食，轻松拥有度假的松弛感。不用担心户外位置叫不到服务人员的情况，carrie，Danil, lisa几位工作人员会随时check用餐情况。家有嗦粉爱好者的朋友们，推荐尝试一下米粉+牛腩+云吞的组合，家中乐宝整碗汤全部喝完。', '["https://dimg04.c-ctrip.com/images/0235b12000anz7lw4CC49_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000anz6p865710_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000anza9xlB01A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000anz6bgjDD31_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000anyzu8u36E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000anz0epbBBAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-13', '花园双床房', '双床房', '家庭亲子', 308, 5.733341276897746, 1, 0.6931471805599453, 1, 0.6931471805599453, 9, '["餐饮设施", "整体满意度", "交通便利性"]'::jsonb, '餐饮设施', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '推荐给长隆玩过之后，想留一天的时间给老广州感受岭南文化的朋友。', '推荐给长隆玩过之后，想留一天的时间给老广州感受岭南文化的朋友。
        酒店在繁华的淘金区，长隆玩过之后打车40分钟左右就到酒店了。因为酒店开业时间早，期望并不高。一进入酒店大堂，我们一家三口就感慨这是此行最满意的酒店了。
         携程白金卡会员订房后可以自动成为岭客汇金卡享受行政酒廊待遇。特别值得体验的是行政酒廊的早餐。推荐户外位置用餐，在瀑布和花园旁享用自助+单点美食，轻松拥有度假的松弛感。不用担心户外位置叫不到服务人员的情况，carrie，Danil, lisa几位工作人员会随时check用餐情况。家有嗦粉爱好者的朋友们，推荐尝试一下米粉+牛腩+云吞的组合，家中乐宝整碗汤全部喝完。', '2023-02-13', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d8e', '酒店设施齐全，房间也很干净整洁，保洁大姐很热情，每次见面都会问有什么需要；前台小姐姐办理入住，讲解很细致；酒店里有自己的花园，风景很好，每天都会带孩子去院子里转转；早餐也特别咱，种类丰富。值得推荐', '["https://dimg04.c-ctrip.com/images/0231s12000aqr7bc00C0C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000aqr6glc93A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000aqr4ndi2F2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-06', '花园双床房', '双床房', '家庭亲子', 98, 4.59511985013459, 0, 0.0, 3, 1.3862943611198906, 8, '["整体满意度", "房间设施", "卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店设施齐全，房间也很干净整洁，保洁大姐很热情，每次见面都会问有什么需要；前台小', '酒店设施齐全，房间也很干净整洁，保洁大姐很热情，每次见面都会问有什么需要；前台小姐姐办理入住，讲解很细致；酒店里有自己的花园，风景很好，每天都会带孩子去院子里转转；早餐也特别咱，种类丰富。值得推荐', '2023-03-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d8f', '集文化，美食，园林景观于一体的酒店。酒店内有博物馆和多家餐厅。日料，味道很不错。早餐，下午茶和欢乐时光都在锦里吧用餐。菜品非常棒，服务也周到。特别是锦里吧的印度籍女生Carre更是贴心。非常棒的体验。', '["https://dimg04.c-ctrip.com/images/0236j12000bi4g7dpF697_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000bi4mdbpDE2C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000bi48g7j449A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000bi4fi08C5C1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000bi4jmkp60CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000bi49uqjF0FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000bi4jxv23D82_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000bi4jpt2ED47_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000bi48mplC746_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-26', '花园双床房', '双床房', '家庭亲子', 100, 4.61512051684126, 0, 0.0, 23, 3.1780538303479458, 8, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '集文化，美食，园林景观于一体的酒店。酒店内有博物馆和多家餐厅。日料，味道很不错。', '集文化，美食，园林景观于一体的酒店。酒店内有博物馆和多家餐厅。日料，味道很不错。早餐，下午茶和欢乐时光都在锦里吧用餐。菜品非常棒，服务也周到。特别是锦里吧的印度籍女生Carre更是贴心。非常棒的体验。', '2023-06-26', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d90', '非常有历史文化感的一个老牌国宾馆似的酒店。首先地理位置真的对于刚来广州的朋友很友好，出门就是地铁淘金站，周围吃饭 打车 都很方便。
老牌酒店的管理和服务接待都做的很好，一进门就有礼宾司的先生帮我们推行李，排队中也有接待人员引导，跟办理入住时候的小姐姐更是亲切惬意的对话，如沐春风。
房间帮我们升级到套房，虽然有些古旧，毕竟老酒店了，但是总的来说性价比超级高了。没有过分超出付出的要求来讲我觉得下次来广州我还会入住。
大堂富丽堂皇中有浓浓岭南风情，主要米其林餐厅好几个都在此酒店，早早预定的我们简直每天下楼就是幸福的感觉～', '["https://dimg04.c-ctrip.com/images/0230712000aorymu402D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000aorzb5fF050_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000aoruz0wC355_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000aos66488DE9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000aoryzmzB292_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000aos6atk090D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000aos5uxqD621_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000aos12y26CC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-18', '花园大床房', '大床房', '其他', 260, 5.564520407322694, 0, 0.0, 17, 2.8903717578961645, 9, '["交通便利性", "前台服务", "性价比"]'::jsonb, '交通便利性', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '非常有历史文化感的一个老牌国宾馆似的酒店。首先地理位置真的对于刚来广州的朋友很友', '非常有历史文化感的一个老牌国宾馆似的酒店。首先地理位置真的对于刚来广州的朋友很友好，出门就是地铁淘金站，周围吃饭 打车 都很方便。
老牌酒店的管理和服务接待都做的很好，一进门就有礼宾司的先生帮我们推行李，排队中也有接待人员引导，跟办理入住时候的小姐姐更是亲切惬意的对话，如沐春风。
房间帮我们升级到套房，虽然有些古旧，毕竟老酒店了，但是总的来说性价比超级高了。没有过分超出付出的要求来讲我觉得下次来广州我还会入住。
大堂富丽堂皇中有浓浓岭南风情，主要米其林餐厅好几个都在此酒店，早早预定的我们简直每天下楼就是幸福的感觉～', '2023-02-18', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d91', '入住广州花园酒店，整体体验非常不错。
酒店的环境优雅，房间宽敞明亮，地理位置位于广州的老中心，环市路核心地段，新装修后的红棉套房现代而不失温馨。房间内的设施齐全，床铺舒适，完全能让人在一天的奔波后能拥有一个安静、舒适的休息空间。
酒店的餐饮选择也很丰富，早餐种类多样，满足了不同客人的口味需求。总的来说，装修后的广州花园酒店绝对是一家值得信赖的酒店，无论是商务出行还是休闲旅游，都能让客人享受到高品质的服务和舒适的住宿环境。特别感谢前台的Betty，工作效率高，态度和蔼可亲，脸上总是洋溢着温暖的笑容。即使在忙碌的时候，她也能迅速办理入住和退房手续，让客人感受到酒店的专业服务。', '["https://dimg04.c-ctrip.com/images/0232u12000ja2lwwcF42E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000ja29yuf81AD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000ja4682b2260_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231r12000ja34qhg203F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000ja3tsz315BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000ja2ii2i2787_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000ja3r7h345F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000ja4depb29FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000ja4es198251_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-24', '花园大床房', '大床房', '商务出差', 289, 5.66988092298052, 0, 0.0, 11, 2.4849066497880004, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '入住广州花园酒店，整体体验非常不错。', '入住广州花园酒店，整体体验非常不错。
酒店的环境优雅，房间宽敞明亮，地理位置位于广州的老中心，环市路核心地段，新装修后的红棉套房现代而不失温馨。房间内的设施齐全，床铺舒适，完全能让人在一天的奔波后能拥有一个安静、舒适的休息空间。
酒店的餐饮选择也很丰富，早餐种类多样，满足了不同客人的口味需求。总的来说，装修后的广州花园酒店绝对是一家值得信赖的酒店，无论是商务出行还是休闲旅游，都能让客人享受到高品质的服务和舒适的住宿环境。特别感谢前台的Betty，工作效率高，态度和蔼可亲，脸上总是洋溢着温暖的笑容。即使在忙碌的时候，她也能迅速办理入住和退房手续，让客人感受到酒店的专业服务。', '2025-03-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d92', '第一次去广州玩选到这个酒店真的很不错，酒店的风景很美池塘里有很多鲤鱼很好看，还有一个很有特色的瀑布餐厅，早上起来看着瀑布吃着早餐很不错，而且交通也很方便去哪都很近，酒店拍照也很美，房间也住的很舒服，住的那个房间可以看见瀑布和一半的广州塔非常好', '["https://dimg04.c-ctrip.com/images/0202q12000anz4wk5BAE5_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0233i12000anyyh40C4C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f12000anyy5saBE35_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000anyzghrF409_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000anys464B8A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000anywbb702E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000anyzmyfC207_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-13', '红棉大床套房', '套房', '情侣出游', 121, 4.804021044733257, 0, 0.0, 3, 1.3862943611198906, 8, '["景观/朝向", "餐饮设施", "交通便利性"]'::jsonb, '景观/朝向', '餐饮设施', '交通便利性', '未知酒店', '未知地点', '匿名', '第一次去广州玩选到这个酒店真的很不错，酒店的风景很美池塘里有很多鲤鱼很好看，还有', '第一次去广州玩选到这个酒店真的很不错，酒店的风景很美池塘里有很多鲤鱼很好看，还有一个很有特色的瀑布餐厅，早上起来看着瀑布吃着早餐很不错，而且交通也很方便去哪都很近，酒店拍照也很美，房间也住的很舒服，住的那个房间可以看见瀑布和一半的广州塔非常好', '2023-02-13', 5, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d93', '每次来广州都想住这家酒店，这次终于订到房间了，过年的原因，办理入住的宾客很多，酒店的服务很细心，还给等待的宾客送了饮料鲜花，整个大堂布置很有年味，后面的花园环境很优美，闹中取静。房间给人感觉有点压抑，走廊和房间的内空都比较矮，入住时安排的房间在五楼，窗户不能打开，而且外面就是平台，窗外没什么景观，而且沙发上还残留长头发，给人第一感觉不是很好，协调前台马上给换了六楼的一间，稍好一点，面盆的龙头是松的，晃晃悠悠，维修部及时修复，洗澡的细节不是很好，每次淋浴都要跨进浴缸，老年人可千万要当心不要摔倒。值得肯定的是酒店服务很到位很热情很专业！', '["https://dimg04.c-ctrip.com/images/0203512000ailm00s44E7_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0236n12000aili6bu6685_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000ailj5dkE494_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000ailjq7sA7D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000ailj9ce5774_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000aili33dED3C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000ailii3x4029_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000ailihvwCD21_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000ailixuy9A25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000ailitkl6EA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-27', '城央绿意双床房', '双床房', '家庭亲子', 269, 5.598421958998375, 1, 0.6931471805599453, 4, 1.6094379124341005, 8, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '每次来广州都想住这家酒店，这次终于订到房间了，过年的原因，办理入住的宾客很多，酒', '每次来广州都想住这家酒店，这次终于订到房间了，过年的原因，办理入住的宾客很多，酒店的服务很细心，还给等待的宾客送了饮料鲜花，整个大堂布置很有年味，后面的花园环境很优美，闹中取静。房间给人感觉有点压抑，走廊和房间的内空都比较矮，入住时安排的房间在五楼，窗户不能打开，而且外面就是平台，窗外没什么景观，而且沙发上还残留长头发，给人第一感觉不是很好，协调前台马上给换了六楼的一间，稍好一点，面盆的龙头是松的，晃晃悠悠，维修部及时修复，洗澡的细节不是很好，每次淋浴都要跨进浴缸，老年人可千万要当心不要摔倒。值得肯定的是酒店服务很到位很热情很专业！', '2023-01-27', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028038e3c98b0941765d95', '酒店卫生干净整洁，环境优雅！舒适！地理位置很好，设施齐全！', '["https://dimg04.c-ctrip.com/images/0236b12000bd5k2eaE332_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000bd5fp17250C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000bd5dv6yF1D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000bd5ehsuD94C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000bd57n2c00E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-06', '花园大床房', '大床房', '商务出差', 29, 3.4011973816621555, 0, 0.0, 4, 1.6094379124341005, 5, '["卫生状况", "整体满意度", "周边配套"]'::jsonb, '卫生状况', '整体满意度', '周边配套', '未知酒店', '未知地点', '匿名', '酒店卫生干净整洁，环境优雅！舒适！地理位置很好，设施齐全！', '酒店卫生干净整洁，环境优雅！舒适！地理位置很好，设施齐全！', '2023-06-06', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d96', '宝藏酒店！入住升级了房型 房间非常大！瀑布餐厅的环境非常好，还有免费的博物馆可以逛！周围也有很多商场 店铺 地铁就在旁边 非常方便', '["https://dimg04.c-ctrip.com/images/0230x12000aulk2me5A4B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000aulq1oh88D5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-04', '花园大床房', '大床房', '家庭亲子', 65, 4.189654742026425, 0, 0.0, 2, 1.0986122886681098, 8, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '宝藏酒店！入住升级了房型 房间非常大！瀑布餐厅的环境非常好，还有免费的博物馆可以', '宝藏酒店！入住升级了房型 房间非常大！瀑布餐厅的环境非常好，还有免费的博物馆可以逛！周围也有很多商场 店铺 地铁就在旁边 非常方便', '2023-04-04', 5, '交通便利性');
