INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d98', '总体而言，我的广州花园酒店之行是一次非常满意的体验。酒店的优雅环境、舒适的客房、美味的餐饮以及前台Nicky等员工的优质服务，都让我的住宿体验变得难忘。我强烈推荐广州花园酒店给那些寻求高品质服务和舒适住宿的旅客。', '["https://dimg04.c-ctrip.com/images/0231l12000hch7hukB7F6_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231512000hch7zltB182_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230g12000hch82xf359B_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-12-22', '花园大床房', '大床房', '朋友出游', 106, 4.672828834461906, 0, 0.0, 17, 2.8903717578961645, 7, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '总体而言，我的广州花园酒店之行是一次非常满意的体验。酒店的优雅环境、舒适的客房、', '总体而言，我的广州花园酒店之行是一次非常满意的体验。酒店的优雅环境、舒适的客房、美味的餐饮以及前台Nicky等员工的优质服务，都让我的住宿体验变得难忘。我强烈推荐广州花园酒店给那些寻求高品质服务和舒适住宿的旅客。', '2024-12-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d99', '酒店的位置非常优越，门口就有地铁，出行便利，酒店的餐厅环境优美，用餐时使人心情愉悦，服务人员也很负责到位。酒店房间设施一般，洗澡只能站在浴缸里，没有喷淋的独立空间，对于老人和儿童很不友好！没有数据线插孔，这个就很不方便，不足之处希望加以改变！', '["https://dimg04.c-ctrip.com/images/0234d12000anbrc1f4BAD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000anbvtou6689_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000anb63cd6E78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231112000anbfhoh8586_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000anb6keyAE52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000anb1kn196B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-02-11', '花园双床房', '双床房', '家庭亲子', 121, 4.804021044733257, 0, 0.0, 6, 1.9459101490553128, 8, '["房间设施", "交通便利性", "餐饮设施"]'::jsonb, '房间设施', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店的位置非常优越，门口就有地铁，出行便利，酒店的餐厅环境优美，用餐时使人心情愉', '酒店的位置非常优越，门口就有地铁，出行便利，酒店的餐厅环境优美，用餐时使人心情愉悦，服务人员也很负责到位。酒店房间设施一般，洗澡只能站在浴缸里，没有喷淋的独立空间，对于老人和儿童很不友好！没有数据线插孔，这个就很不方便，不足之处希望加以改变！', '2023-02-11', 4, '房间设施');
