INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d9b', '酒店服务很好，下车就有人帮拿行李，大堂大气，办理入住井然有序，我非周末节假日去的正好人不算多，亲子房很大，很干净小朋友超级开心，酒店真的有个花园，好多花花草草锦鲤，18米瀑布也是亮点', '["https://dimg04.c-ctrip.com/images/0231612000apcifcy12AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000apc0l3eB132_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000apcfxrwE80D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000apbqzs52707_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-23', '大嘴猴亲子主题大床房', '主题房', '家庭亲子', 91, 4.5217885770490405, 0, 0.0, 13, 2.6390573296152584, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店服务很好，下车就有人帮拿行李，大堂大气，办理入住井然有序，我非周末节假日去的', '酒店服务很好，下车就有人帮拿行李，大堂大气，办理入住井然有序，我非周末节假日去的正好人不算多，亲子房很大，很干净小朋友超级开心，酒店真的有个花园，好多花花草草锦鲤，18米瀑布也是亮点', '2023-02-23', 5, '整体满意度');
