INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d9d', '酒店非常的不错，景色很美，设备很齐全！入住的时候看到有小孩，免费给酒店做了升级！前台Becity Charies态度非常的好！非常不错的体验。', '["https://dimg04.c-ctrip.com/images/0236i12000asomfopC89C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-21', '花园大床房', '大床房', '家庭亲子', 71, 4.276666119016055, 0, 0.0, 5, 1.791759469228055, 7, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '酒店非常的不错，景色很美，设备很齐全！入住的时候看到有小孩，免费给酒店做了升级！', '酒店非常的不错，景色很美，设备很齐全！入住的时候看到有小孩，免费给酒店做了升级！前台Becity Charies态度非常的好！非常不错的体验。', '2023-03-21', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d9e', '总体体验非常棒的酒店，能感受到丰富的文化底蕴。前台的rivia小姐姐态度友善，脸上永远挂着笑容，耐心的讲解酒店入住的注意事项，还贴心的建议我们尽快去酒廊体验下午茶，替我们担心时间来不及。
酒店处处都是景，负责讲解25个打卡点的老师非常认真细致，让人觉得住在花园酒店根本不需要出门，酒店内的景点就足够你细细品味，博物馆也超出预期，有清晰的参观线索、丰富的藏品和精彩的说不完的背后故事。
两天一晚接近24小时的时间过得很快，我们基本打卡了酒店里所有的景点、餐厅、博物馆、健身房、泳池，这是一座近现代文化交融的酒店，你既能从很多细节中找寻到中国酒店业发展的记忆，也能不经意间感受到酒店努力拥抱现代化、不断创新紧跟时代的步伐，既能体会到成熟完善的硬件设施带给你的处处方便，也能享受到热情体贴的酒店工作人员展现出的人文关怀。这是一座你入住其他诸如万豪、希尔顿、洲际、凯悦等豪华酒店所无法体会到的独特感受，一份只属于广州花园酒店的特别记忆。', '["https://dimg04.c-ctrip.com/images/0234q12000c5zp0hfAF98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000c5zrrfwCBDF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000c5zoo38AEDF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000c5zn38wB67E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-17', '红棉大床套房', '套房', '情侣出游', 416, 6.0330862217988015, 0, 0.0, 1, 0.6931471805599453, 10, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '总体体验非常棒的酒店，能感受到丰富的文化底蕴。前台的rivia小姐姐态度友善，脸', '总体体验非常棒的酒店，能感受到丰富的文化底蕴。前台的rivia小姐姐态度友善，脸上永远挂着笑容，耐心的讲解酒店入住的注意事项，还贴心的建议我们尽快去酒廊体验下午茶，替我们担心时间来不及。
酒店处处都是景，负责讲解25个打卡点的老师非常认真细致，让人觉得住在花园酒店根本不需要出门，酒店内的景点就足够你细细品味，博物馆也超出预期，有清晰的参观线索、丰富的藏品和精彩的说不完的背后故事。
两天一晚接近24小时的时间过得很快，我们基本打卡了酒店里所有的景点、餐厅、博物馆、健身房、泳池，这是一座近现代文化交融的酒店，你既能从很多细节中找寻到中国酒店业发展的记忆，也能不经意间感受到酒店努力拥抱现代化、不断创新紧跟时代的步伐，既能体会到成熟完善的硬件设施带给你的处处方便，也能享受到热情体贴的酒店工作人员展现出的人文关怀。这是一座你入住其他诸如万豪、希尔顿、洲际、凯悦等豪华酒店所无法体会到的独特感受，一份只属于广州花园酒店的特别记忆。', '2023-09-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028043e3c98b0941765d9f', '非常漂亮，感谢Tony给我们做了升房，非常满意的一次旅程', '["https://dimg04.c-ctrip.com/images/0236z2234bfiprpw0BEE7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z2234bfiprxluD16B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231r2224vc5jplvkDA10_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h2224vc5jptldB643_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023522215f8sdnhv5E8F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-06', '花园双床房', '双床房', '情侣出游', 28, 3.367295829986474, 0, 0.0, 2, 1.0986122886681098, 4, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '非常漂亮，感谢Tony给我们做了升房，非常满意的一次旅程', '非常漂亮，感谢Tony给我们做了升房，非常满意的一次旅程', '2023-06-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da0', '一进酒店大堂就被震惊了，礼宾部的小哥哥都好热情，服务非常好。酒店的花园超级漂亮，小朋友每天都要去打卡～', '["https://dimg04.c-ctrip.com/images/0236l12000b1h2ped85BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000b1gwczb44BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000b1h3eua468E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000b1gy72f15D2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000b1gv5xvC195_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000b1gkvza9412_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-23', '花园大床房', '大床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 12, 2.5649493574615367, 6, '["前台服务", "公共设施"]'::jsonb, '前台服务', '公共设施', NULL, '未知酒店', '未知地点', '匿名', '一进酒店大堂就被震惊了，礼宾部的小哥哥都好热情，服务非常好。酒店的花园超级漂亮，', '一进酒店大堂就被震惊了，礼宾部的小哥哥都好热情，服务非常好。酒店的花园超级漂亮，小朋友每天都要去打卡～', '2023-04-23', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da1', '让人印象深刻的一次行程。
本来趁着疫情放开，客流不大来广州。
预订了一个套房，三个人，前台的小姐姐还帮我卖做了升级，送了鲜花和宝格丽的礼物。
房间视野开阔，面对着白云山，楼下就是地铁站。
酒店的布局很有特色，院子中有个瀑布，营造了自然的氛围。
