INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da4', '酒店虽老一些，但是服务意识特别的好，前台办理入住的小姐姐很有耐心，也帮我们留了高楼层的房间。还送了花和小饼干。早餐特别丰富，整体还是很好的。', '["https://dimg04.c-ctrip.com/images/0231212000asf6qxb29CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000asf0z9bE9CC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-19', '红棉大床套房', '套房', '商务出差', 70, 4.262679877041316, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店虽老一些，但是服务意识特别的好，前台办理入住的小姐姐很有耐心，也帮我们留了高', '酒店虽老一些，但是服务意识特别的好，前台办理入住的小姐姐很有耐心，也帮我们留了高楼层的房间。还送了花和小饼干。早餐特别丰富，整体还是很好的。', '2023-03-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da5', '这个酒店入住给我们留下了非常不好的印象
不明白为什么会这样
希望管理层重视起来
1，checkin效率低，办理入住30分钟，大厅排队很长
2，2点入住，结果三点半，到酒店告诉我房间没有打扫好，只能先给一间，我们安排老人带孩子先休息，两个人疲惫的在附近转悠了一个半小时（五点）房间还没有打扫好，在我们的争取下给我们安排了顶层，结果房间在消防通道旁边，床很小，设施成旧，没有淋浴间，只有一个老式浴缸，很无语……
3，针对这些问题，酒店没有任何态度，只能说让我们等
携程客服积极的给我们处理了，但是还是有点失望??
客观的说，酒店位置挺好，旁边就是地铁，停车场也挺方便，酒店的花园应该是两点', '["https://dimg04.c-ctrip.com/images/0232q12000ak1cec416B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236s12000ak1ahi471E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000ak12zl10BA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000ak1cech9B94_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-02-01', '花园双床房', '双床房', '家庭亲子', 293, 5.683579767338681, 3, 1.3862943611198906, 21, 3.091042453358316, 8, '["退房/入住效率", "房间设施", "前台服务"]'::jsonb, '退房/入住效率', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '这个酒店入住给我们留下了非常不好的印象', '这个酒店入住给我们留下了非常不好的印象
