INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da7', '优点：服务非常好，不愧为广州老牌五星级的酒店。地理位置绝佳，门口就有地铁（5号线淘金站），对面就是广州酒家和白云宾馆，附近步行可到陶陶居，五号线坐五站珠江新城出来就是花城大道，看广州塔夜景的极佳位置。
不足：设施老化，毕竟上世纪八十年代的酒店，不过维护的还可以，也算卫生；早餐品种和质量感觉对不起这个价格和五星级酒店的身份，早餐质量感觉也就国内中档酒店比如亚朵的水平，而且空间很小，八点半后去基本需要排队等座。
整体感觉还是蛮好的，在广州五星酒店里价格相对亲民，应该还会再次选择花园酒店。
祝生意兴隆。', '["https://dimg04.c-ctrip.com/images/0235u12000alnwi28C0C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000aln24kvB928_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000alnty7y7F26_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-05', '花园大床房', '大床房', '家庭亲子', 253, 5.537334267018537, 0, 0.0, 2, 1.0986122886681098, 9, '["交通便利性", "性价比", "餐饮设施"]'::jsonb, '交通便利性', '性价比', '餐饮设施', '未知酒店', '未知地点', '匿名', '优点：服务非常好，不愧为广州老牌五星级的酒店。地理位置绝佳，门口就有地铁（5号线', '优点：服务非常好，不愧为广州老牌五星级的酒店。地理位置绝佳，门口就有地铁（5号线淘金站），对面就是广州酒家和白云宾馆，附近步行可到陶陶居，五号线坐五站珠江新城出来就是花城大道，看广州塔夜景的极佳位置。
