INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da8', '预订了基础的房型，体验入住感一般。酒店地理位置很好，出行交通方便，门口就有地铁站，但对开车客人来说非常不方便，地面停车场每次进出都要去大堂输入车牌号，没人告知过，为此来回跑过两次，而且大堂输入车牌信息的位置经常没人等待很久。
另外这次和家人入住是两晚，第二晚时候突然想在酒店用早餐办理付费过后前台送了几包欢迎小饼干，这欢迎小饼干难道不该在我办理入住的时候送吗？？付完早餐钱想起来自己是岭客汇金卡，但是办理入住的时候并没有升级房型、早餐等服务，经过协商，付的早餐钱退给了我，会员的两次单早并成一次双早。不知道这会员权益是该自己讨还是前台关注的，体验感不是很好。
不过酒店的花园还有博物馆有时间还是推荐逛一逛的', '["https://dimg04.c-ctrip.com/images/0236p12000atjmpo24177_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000atjp7125973_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000atjo8226AE0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-03-28', '花园大床房', '大床房', '家庭亲子', 303, 5.717027701406222, 1, 0.6931471805599453, 5, 1.791759469228055, 8, '["交通便利性", "前台服务", "周边配套"]'::jsonb, '交通便利性', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '预订了基础的房型，体验入住感一般。酒店地理位置很好，出行交通方便，门口就有地铁站', '预订了基础的房型，体验入住感一般。酒店地理位置很好，出行交通方便，门口就有地铁站，但对开车客人来说非常不方便，地面停车场每次进出都要去大堂输入车牌号，没人告知过，为此来回跑过两次，而且大堂输入车牌信息的位置经常没人等待很久。
另外这次和家人入住是两晚，第二晚时候突然想在酒店用早餐办理付费过后前台送了几包欢迎小饼干，这欢迎小饼干难道不该在我办理入住的时候送吗？？付完早餐钱想起来自己是岭客汇金卡，但是办理入住的时候并没有升级房型、早餐等服务，经过协商，付的早餐钱退给了我，会员的两次单早并成一次双早。不知道这会员权益是该自己讨还是前台关注的，体验感不是很好。
不过酒店的花园还有博物馆有时间还是推荐逛一逛的', '2023-03-28', 3, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028052e3c98b0941765da9', '房间高度很日式有点压抑，服务很好KRISTT小姐姐主动帮助退房，旁边有很多好吃酒家，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0230x12000b1p2uom0D85_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000b1phyg10ED5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t12000b1p8dejFBDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-04-24', '花园双床房', '双床房', '家庭亲子', 49, 3.912023005428146, 0, 0.0, 51, 3.951243718581428, 7, '["前台服务", "周边配套", "整体满意度"]'::jsonb, '前台服务', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '房间高度很日式有点压抑，服务很好KRISTT小姐姐主动帮助退房，旁边有很多好吃酒', '房间高度很日式有点压抑，服务很好KRISTT小姐姐主动帮助退房，旁边有很多好吃酒家，下次还会入住。', '2023-04-24', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765daa', '第一次住花园酒店，升级了行政套房．房间很大有书房健身房．洗手间也有二间，太棒了，看夜景也很宽阔，卫生干净，服务周到！花园里的风景好看，还有瀑布', '["https://dimg04.c-ctrip.com/images/0230u12000b7d81wo7CDB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000b7dc72b41B5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000b7d1ln95D3E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-12', '花园双床房', '双床房', '朋友出游', 71, 4.276666119016055, 0, 0.0, 11, 2.4849066497880004, 8, '["房间设施", "整体满意度", "卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '第一次住花园酒店，升级了行政套房．房间很大有书房健身房．洗手间也有二间，太棒了，', '第一次住花园酒店，升级了行政套房．房间很大有书房健身房．洗手间也有二间，太棒了，看夜景也很宽阔，卫生干净，服务周到！花园里的风景好看，还有瀑布', '2023-05-12', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765dab', '设施：大气的厅堂，快速的电梯，整体硬件不错。房间比较温馨，略小，尤其是卫生间和淋浴间太小了点。
卫生：不错，尤其是9楼打扫的人员总是反复确认要帮忙打扫，假期人多还能这样很赞！
服务：有好有坏，办理入住等待的人很多，有贴心的发小发夹和汽水，缓解等待的着急情绪。办理入住的Ken服务很好，因为是中秋还送了月饼。
不好的地方，下车没有人帮取行李，因为独自带孩子有两个箱子，招呼了门童才不情愿的拿了一下；瀑布餐厅煎蛋的大叔态度不友好，说话阴阳怪气！
早餐：看评论这个酒店是餐饮著称，但遗憾的是早餐很普通，分别在一楼和30楼吃了，没有什么特色，可选的也是有限，8点以后就要排队。早餐最大的亮点是到12点，可以不必太匆忙！
环境：非常好，毕竟叫花园酒店！', '["https://dimg04.c-ctrip.com/images/0235l12000cc5r5jj8D45_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000cc5jyb8F0FA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-10-06', '城央绿意大床房', '大床房', '家庭亲子', 321, 5.7745515455444085, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "餐饮设施", "房间设施"]'::jsonb, '前台服务', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '设施：大气的厅堂，快速的电梯，整体硬件不错。房间比较温馨，略小，尤其是卫生间和淋', '设施：大气的厅堂，快速的电梯，整体硬件不错。房间比较温馨，略小，尤其是卫生间和淋浴间太小了点。
卫生：不错，尤其是9楼打扫的人员总是反复确认要帮忙打扫，假期人多还能这样很赞！
服务：有好有坏，办理入住等待的人很多，有贴心的发小发夹和汽水，缓解等待的着急情绪。办理入住的Ken服务很好，因为是中秋还送了月饼。
