早餐：看评论这个酒店是餐饮著称，但遗憾的是早餐很普通，分别在一楼和30楼吃了，没有什么特色，可选的也是有限，8点以后就要排队。早餐最大的亮点是到12点，可以不必太匆忙！
环境：非常好，毕竟叫花园酒店！', '2023-10-06', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765dac', '一如继往的优秀，主要服务一流，工作人员礼貌客气。地段好性价比高。外国客人很多，酒店代收了很多快递帮忙整理。', '["https://dimg04.c-ctrip.com/images/0236f4234bodg3f7431AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-28', '花园大床房', '大床房', '商务出差', 53, 3.9889840465642745, 0, 0.0, 54, 4.007333185232471, 7, '["前台服务", "性价比", "交通便利性"]'::jsonb, '前台服务', '性价比', '交通便利性', '未知酒店', '未知地点', '匿名', '一如继往的优秀，主要服务一流，工作人员礼貌客气。地段好性价比高。外国客人很多，酒', '一如继往的优秀，主要服务一流，工作人员礼貌客气。地段好性价比高。外国客人很多，酒店代收了很多快递帮忙整理。', '2023-06-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765dad', '花园酒店声名在外，最早的合资五星级酒店，作为广州人的我，竟然到了2023年春节，才有机会感受她的风采!疫情过后复常神速，从上海回来特地选了她，结果上海话一路不绝于耳，不说地点还以为自己没有离开上海!
Doorman: 有分寸感的礼貌，很好。
Lobby: 很久没有看见这样热闹的节日氛围，喜欢。
Check in: 春节期间超长等待房间已是常态，没办法。
红棉大床房: 房间老旧面积颇大，听说装修排期中。
服务: 我的 Housekeeping 是整个行程的精华，超棒。
饮食: 荔湾亭失望/自助餐无感/酒吧这个烤蔬菜一流。
总结: I will be back! Thank you!', '["https://dimg04.c-ctrip.com/images/0232x12000asojozu10FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000asoe5c9832A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234l12000ajiv7ww17CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000asogtwj523B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-03-21', '红棉大床套房', '套房', '其他', 293, 5.683579767338681, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "客房服务", "房间设施"]'::jsonb, '整体满意度', '客房服务', '房间设施', '未知酒店', '未知地点', '匿名', '花园酒店声名在外，最早的合资五星级酒店，作为广州人的我，竟然到了2023年春节，', '花园酒店声名在外，最早的合资五星级酒店，作为广州人的我，竟然到了2023年春节，才有机会感受她的风采!疫情过后复常神速，从上海回来特地选了她，结果上海话一路不绝于耳，不说地点还以为自己没有离开上海!
Doorman: 有分寸感的礼貌，很好。
Lobby: 很久没有看见这样热闹的节日氛围，喜欢。
Check in: 春节期间超长等待房间已是常态，没办法。
红棉大床房: 房间老旧面积颇大，听说装修排期中。
服务: 我的 Housekeeping 是整个行程的精华，超棒。
饮食: 荔湾亭失望/自助餐无感/酒吧这个烤蔬菜一流。
总结: I will be back! Thank you!', '2023-03-21', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765dae', '酒店交通出行方便，客房舒适，配套设施齐全，风景优美，中西美食俱全。特别是Carol 小姐很专业，善解人意，喜欢住这里，还会再来。', '["https://dimg04.c-ctrip.com/images/0231z12000cd1qo0f2AD1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000cd1qoql427F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-09', '花园双床房', '双床房', '朋友出游', 64, 4.174387269895637, 0, 0.0, 3, 1.3862943611198906, 6, '["交通便利性", "整体满意度", "餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店交通出行方便，客房舒适，配套设施齐全，风景优美，中西美食俱全。特别是Caro', '酒店交通出行方便，客房舒适，配套设施齐全，风景优美，中西美食俱全。特别是Carol 小姐很专业，善解人意，喜欢住这里，还会再来。', '2023-10-09', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765daf', '每次和儿子去动物园都住这里，这次入住太差了，开房门后房间里面还有客户搞的自己马上退出来了，换另外一个房间又等半小时而且房间空气清新剂味道太重，五星级就这待遇，如果不是近动物园真心不选择。', '["https://dimg04.c-ctrip.com/images/0233g12000apaia7p85C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000apage7mD3CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000apa86y07F06_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000apa7rmn6DC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-02-22', '粤韵大床套房', '套房', '家庭亲子', 93, 4.543294782270004, 0, 0.0, 14, 2.70805020110221, 7, '["退房/入住效率", "客房服务", "整体满意度"]'::jsonb, '退房/入住效率', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '每次和儿子去动物园都住这里，这次入住太差了，开房门后房间里面还有客户搞的自己马上', '每次和儿子去动物园都住这里，这次入住太差了，开房门后房间里面还有客户搞的自己马上退出来了，换另外一个房间又等半小时而且房间空气清新剂味道太重，五星级就这待遇，如果不是近动物园真心不选择。', '2023-02-22', 3, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765db0', '在携程花1474元定了该酒店27日入住的64平米的粤韵1.3米双床套房，在前台登记入住时说房间没打扫出来，可以免费升级成行政套房，结果该套房又旧又破，沙发又脏又破，马桶老旧，灯好几盏不亮，这种也好意思叫升级房型？这种欺骗消费者的行为，不讲信誉的行为，发生老牌的五星级酒店，真是让心寒。再三协调要求换回原定房型，先是说没有了，晚上七点半再找到经理说，有房岀来，但打扫需要二个半小时，一直到了晚上十一点，孩子已经睡了，只有放弃换房。该酒店这种忽悠消费者，借节假日客房销售旺季，卖老旧客房的行为，让人就像吃了个苍蝇一样恶心。', '["https://dimg04.c-ctrip.com/images/0231k12000aj0zdm4C7D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000aj12ihb623E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000aj0x4dxBBD1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236g12000aj12roy1490_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233412000aj0yc6gADD4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000aj133812B2D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.0, 1, '2023-01-28', '粤韵双床套房', '套房', '家庭亲子', 259, 5.560681631015528, 15, 2.772588722239781, 1, 0.6931471805599453, 9, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '在携程花1474元定了该酒店27日入住的64平米的粤韵1.3米双床套房，在前台登', '在携程花1474元定了该酒店27日入住的64平米的粤韵1.3米双床套房，在前台登记入住时说房间没打扫出来，可以免费升级成行政套房，结果该套房又旧又破，沙发又脏又破，马桶老旧，灯好几盏不亮，这种也好意思叫升级房型？这种欺骗消费者的行为，不讲信誉的行为，发生老牌的五星级酒店，真是让心寒。再三协调要求换回原定房型，先是说没有了，晚上七点半再找到经理说，有房岀来，但打扫需要二个半小时，一直到了晚上十一点，孩子已经睡了，只有放弃换房。该酒店这种忽悠消费者，借节假日客房销售旺季，卖老旧客房的行为，让人就像吃了个苍蝇一样恶心。', '2023-01-28', 1, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765db1', '超级满意的家庭出行选择。选择花园酒店式最正确的啦，粉色仙女小姐姐也温柔又漂亮，semmy小姐姐也超级贴心。
