INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802805ee3c98b0941765db3', '春节期间服务有点跟不上，但是态度都还挺好的，一开始定的房间来不及打扫给安排了公寓房，设施可以说非常老旧，难得的是打扫得很干净没有异味，维护的也不错，后面安排到了我自己定的房间还送了三天的早餐，就很好解决了问题。
广州有很多新的高级酒店，但是广州花园酒店的氛围和底蕴是新的酒店无法比拟的，老市区的大花园的即视感，下午茶也很不错', '["https://dimg04.c-ctrip.com/images/0234i12000anujbew9B20_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000anusl4y2ECD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230v12000anu95wuE6C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000anuujy2FA6D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000antat158A51_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000anu79o8F952_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-13', '红棉大床套房', '套房', '家庭亲子', 162, 5.093750200806762, 0, 0.0, 10, 2.3978952727983707, 9, '["整体满意度", "客房服务", "卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '春节期间服务有点跟不上，但是态度都还挺好的，一开始定的房间来不及打扫给安排了公寓', '春节期间服务有点跟不上，但是态度都还挺好的，一开始定的房间来不及打扫给安排了公寓房，设施可以说非常老旧，难得的是打扫得很干净没有异味，维护的也不错，后面安排到了我自己定的房间还送了三天的早餐，就很好解决了问题。
广州有很多新的高级酒店，但是广州花园酒店的氛围和底蕴是新的酒店无法比拟的，老市区的大花园的即视感，下午茶也很不错', '2023-02-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765db4', '性价比很高的一家酒店，客房和礼宾服务不错。一进门就能闻到香香的味道。不过，前台感觉有点搞不清楚订单情况，我分开预定了2个订单，一个1晚，一个3晚，入住前一天酒店电话我确认了一共2间4晚，办理入住的时候前台说1晚，然后我提醒她有两个订单，才发现是4晚，搞了15分钟吧，当时12点多房间还没打扫出来，我们先外出了，下午2点电话我说可以来拿房卡了，等我4点回来拿房卡，换了个前台，大概又搞不清楚了？又等了5分钟，怎么拿个房卡那么难。。。等第二天游玩回来，进不了房门了，刷不了卡，我猜测真的只做了1晚，但是从头到尾说的都是4晚。吃力。。除此以外其他都挺好的。喜欢酒店内的后花园！', '["https://dimg04.c-ctrip.com/images/0232g12000ak1314h2497_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000ak128qsF587_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000ak1cedk2C1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-01', '花园大床房', '大床房', '家庭亲子', 285, 5.655991810819852, 0, 0.0, 27, 3.332204510175204, 8, '["前台服务", "退房/入住效率", "性价比"]'::jsonb, '前台服务', '退房/入住效率', '性价比', '未知酒店', '未知地点', '匿名', '性价比很高的一家酒店，客房和礼宾服务不错。一进门就能闻到香香的味道。不过，前台感', '性价比很高的一家酒店，客房和礼宾服务不错。一进门就能闻到香香的味道。不过，前台感觉有点搞不清楚订单情况，我分开预定了2个订单，一个1晚，一个3晚，入住前一天酒店电话我确认了一共2间4晚，办理入住的时候前台说1晚，然后我提醒她有两个订单，才发现是4晚，搞了15分钟吧，当时12点多房间还没打扫出来，我们先外出了，下午2点电话我说可以来拿房卡了，等我4点回来拿房卡，换了个前台，大概又搞不清楚了？又等了5分钟，怎么拿个房卡那么难。。。等第二天游玩回来，进不了房门了，刷不了卡，我猜测真的只做了1晚，但是从头到尾说的都是4晚。吃力。。除此以外其他都挺好的。喜欢酒店内的后花园！', '2023-02-01', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765db5', '酒店超出预期，真的有大花园，自助早餐晚餐都超级棒，亲子套餐下午还送了点心，小朋友也非常喜欢房间的布置，整体非常用心，总之下次来广州玩还会选择再次入住！唯一的缺点就是入住率太满，人比较多，春节期间明显人手不够～', '["https://dimg04.c-ctrip.com/images/0230m12000aju59mb35CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000aju6nz9BA7B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000aju6mav6EB2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000aju3fu6BA86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000aju4wlpF198_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000aju6s74A488_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000aju6d4b1C65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000aju4sm44E06_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000aju4qdc1235_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-01', '羊羊得意主题大床房', '主题房', '家庭亲子', 104, 4.653960350157523, 0, 0.0, 17, 2.8903717578961645, 8, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店超出预期，真的有大花园，自助早餐晚餐都超级棒，亲子套餐下午还送了点心，小朋友', '酒店超出预期，真的有大花园，自助早餐晚餐都超级棒，亲子套餐下午还送了点心，小朋友也非常喜欢房间的布置，整体非常用心，总之下次来广州玩还会选择再次入住！唯一的缺点就是入住率太满，人比较多，春节期间明显人手不够～', '2023-02-01', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765db6', '作为有名的老牌酒店，酒店地理位置非常便捷，建筑和景观设计没的说，非常美。只是设施稍显陈旧一点点，虽然看得出是精心设计使用挺便捷，但其实房间小可以不设置浴缸，活动空间会更大。', '["https://dimg04.c-ctrip.com/images/0231512000arc1vikD552_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000arbyt6m022B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-03-10', '花园大床房', '大床房', '情侣出游', 86, 4.465908118654584, 0, 0.0, 8, 2.19722457733622, 8, '["房间设施", "交通便利性", "景观/朝向"]'::jsonb, '房间设施', '交通便利性', '景观/朝向', '未知酒店', '未知地点', '匿名', '作为有名的老牌酒店，酒店地理位置非常便捷，建筑和景观设计没的说，非常美。只是设施', '作为有名的老牌酒店，酒店地理位置非常便捷，建筑和景观设计没的说，非常美。只是设施稍显陈旧一点点，虽然看得出是精心设计使用挺便捷，但其实房间小可以不设置浴缸，活动空间会更大。', '2023-03-10', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765db7', '本人在当天下午13时左右到前台拿房，下面这个服务员帮我办理，他说，由于节日房间没打扫卫生，叫我在下午15时到前台找他拿房卡，;我问他说，你来时来到找我就可以了。本人在下午15时到他处，找他拿房卡，他竟然叫我去排队等候，我没排队，叫他找个同事帮我处理，他根本不理我，后来我找到另外一名服务员，拿房不到的原因，是房间没打扫卫生，这样就是酒店的不对了。这就是我们国家的五星级酒店？服务员大冷漠，服务有提升的空间，特别是下面这名服务员。希望携程能了解一下，谢谢。', '["https://dimg04.c-ctrip.com/images/0230q12000aiid5wb836B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000aiigqh969F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-01-26', '城央绿意大床房', '大床房', '情侣出游', 227, 5.429345628954441, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '本人在当天下午13时左右到前台拿房，下面这个服务员帮我办理，他说，由于节日房间没', '本人在当天下午13时左右到前台拿房，下面这个服务员帮我办理，他说，由于节日房间没打扫卫生，叫我在下午15时到前台找他拿房卡，;我问他说，你来时来到找我就可以了。本人在下午15时到他处，找他拿房卡，他竟然叫我去排队等候，我没排队，叫他找个同事帮我处理，他根本不理我，后来我找到另外一名服务员，拿房不到的原因，是房间没打扫卫生，这样就是酒店的不对了。这就是我们国家的五星级酒店？服务员大冷漠，服务有提升的空间，特别是下面这名服务员。希望携程能了解一下，谢谢。', '2023-01-26', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765db8', '年初三带父母来住，年前预订的时候选择了红棉大床房，订前和酒店电话确认过是可以加床的，也在订单的备注里明确要求了。红棉大床有2米宽，我睡加床，父母睡大床，这样父母可以睡的比较舒服。结果在入住前一晚电话告知我有可能无法加床，能否接受换房，我说尽量加床，实在不行换房也是可以的。
到了办理入住的时候前台告诉我床已经不够了，前台给我的选项是1.加钱换粤韵的双床房，现在入住 2.等到四点再入住，到时候电话告知是否有床。如果到时候还是没床就只能三个人住大床房??
粤韵的双床只有1.3米宽，两个成人睡很不舒服。我问前台能不能先保留这间双床房，等到四点能加床就在原房型加床，不能就换到粤韵双床。结果前台告诉我房间是一定不会保留到四点的，到四点也不一定有床可加??
我还能说什么？只能赶紧定下这间双床房。1.3的双床睡两个成人是很不舒服的，晚上父母也并没有睡好。酒店承诺可以加床却无法兑现，也完全没为顾客提供任何解决措施，前台全程冷漠脸，毫无歉意，这就是岭南集团的服务水平？', '["https://dimg04.c-ctrip.com/images/0235412000aisc5nrEC60_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000aisbqc0EBFC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-01-27', '红棉大床套房', '套房', '家庭亲子', 430, 6.066108090103747, 4, 1.6094379124341005, 3, 1.3862943611198906, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '年初三带父母来住，年前预订的时候选择了红棉大床房，订前和酒店电话确认过是可以加床', '年初三带父母来住，年前预订的时候选择了红棉大床房，订前和酒店电话确认过是可以加床的，也在订单的备注里明确要求了。红棉大床有2米宽，我睡加床，父母睡大床，这样父母可以睡的比较舒服。结果在入住前一晚电话告知我有可能无法加床，能否接受换房，我说尽量加床，实在不行换房也是可以的。
到了办理入住的时候前台告诉我床已经不够了，前台给我的选项是1.加钱换粤韵的双床房，现在入住 2.等到四点再入住，到时候电话告知是否有床。如果到时候还是没床就只能三个人住大床房??
粤韵的双床只有1.3米宽，两个成人睡很不舒服。我问前台能不能先保留这间双床房，等到四点能加床就在原房型加床，不能就换到粤韵双床。结果前台告诉我房间是一定不会保留到四点的，到四点也不一定有床可加??
我还能说什么？只能赶紧定下这间双床房。1.3的双床睡两个成人是很不舒服的，晚上父母也并没有睡好。酒店承诺可以加床却无法兑现，也完全没为顾客提供任何解决措施，前台全程冷漠脸，毫无歉意，这就是岭南集团的服务水平？', '2023-01-27', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765db9', '临时决定到的广州，提前在网上订了住宿，看到推荐，对花园酒店很感兴趣，定了一间红棉大床房。住宿的前一天就接到酒店电话，询问第二天到店时间，以及同行是否有老人孩子。住宿当天下午一点到的，可能春节期间人多，办理住宿真的很耗费时间，前台的小姐姐们都跟有耐心，就是腾房间的速度真的是有待改进。满分送给酒店里所有服务人员，很贴心，很有耐心。酒店房间可以看到后花园，忘了拍照了。早晨睡了懒觉，在荔湾亭用了自助餐，很不错。下次有机会来广州还会选择住这里。对了，离地铁口也很近，很方便。', '["https://dimg04.c-ctrip.com/images/0230712000aih0mxc1D48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000aigzz20FB07_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000aih0b5v9F4F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-26', '红棉大床套房', '套房', '家庭亲子', 234, 5.459585514144159, 1, 0.6931471805599453, 1, 0.6931471805599453, 8, '["前台服务", "退房/入住效率", "交通便利性"]'::jsonb, '前台服务', '退房/入住效率', '交通便利性', '未知酒店', '未知地点', '匿名', '临时决定到的广州，提前在网上订了住宿，看到推荐，对花园酒店很感兴趣，定了一间红棉', '临时决定到的广州，提前在网上订了住宿，看到推荐，对花园酒店很感兴趣，定了一间红棉大床房。住宿的前一天就接到酒店电话，询问第二天到店时间，以及同行是否有老人孩子。住宿当天下午一点到的，可能春节期间人多，办理住宿真的很耗费时间，前台的小姐姐们都跟有耐心，就是腾房间的速度真的是有待改进。满分送给酒店里所有服务人员，很贴心，很有耐心。酒店房间可以看到后花园，忘了拍照了。早晨睡了懒觉，在荔湾亭用了自助餐，很不错。下次有机会来广州还会选择住这里。对了，离地铁口也很近，很方便。', '2023-01-26', 5, '前台服务');
