INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765dbb', '环境很好。 
 瀑布餐厅自助很美味。尤其牛肉粉很正宗。唯一不足是大堂找点热水让孩子喝，就不给。明明有热水器图七。主要是排队办理入住时间太长，所以想讨杯热水，大堂吧的服务员直接冷脸说没有。2099元的消费瞬间觉得不值了。', '["https://dimg04.c-ctrip.com/images/0231512000ai11zgb2981_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000ai0zpxt7706_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000ai10czb4DE1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000ai11ftx45B5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000ai111ws85F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000ai116ziB847_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000ai12beb60B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-24', '大嘴猴亲子主题大床房', '主题房', '家庭亲子', 109, 4.700480365792417, 2, 1.0986122886681098, 1, 0.6931471805599453, 8, '["前台服务", "餐饮设施", "性价比"]'::jsonb, '前台服务', '餐饮设施', '性价比', '未知酒店', '未知地点', '匿名', '环境很好。 ', '环境很好。 
 瀑布餐厅自助很美味。尤其牛肉粉很正宗。唯一不足是大堂找点热水让孩子喝，就不给。明明有热水器图七。主要是排队办理入住时间太长，所以想讨杯热水，大堂吧的服务员直接冷脸说没有。2099元的消费瞬间觉得不值了。', '2023-01-24', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765dbc', '2016年第一次带孩子入住留下了非常好的印象，所以2023年带家人来广州依然选择这里。虽然酒店设备老旧了一些，但位置、设施、环境卫生等还是不错的。住了六天唯一非常不开心的是房间的安排！带着老人孩子希望两间房间能稍微近一些，被告知过年人太多只能一个安排在18楼，一个安排在5楼，我仔细看订单我定的应该是18到21楼！而且5楼明显和18楼的房间不一样！可气的是办理的前台小哥是不是觉得北方人好糊弄，给我们的房号1847和524，恨不得把不好的房号和房间都安排给我们，因为比较晚了而且带着老人孩子，大过年的也就没有在争论。不会再去了！', '["https://dimg04.c-ctrip.com/images/0233612000ajcu93hC37E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000ajcusqf389C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-29', '花园大床房', '大床房', '家庭亲子', 264, 5.579729825986222, 2, 1.0986122886681098, 5, 1.791759469228055, 8, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '2016年第一次带孩子入住留下了非常好的印象，所以2023年带家人来广州依然选择', '2016年第一次带孩子入住留下了非常好的印象，所以2023年带家人来广州依然选择这里。虽然酒店设备老旧了一些，但位置、设施、环境卫生等还是不错的。住了六天唯一非常不开心的是房间的安排！带着老人孩子希望两间房间能稍微近一些，被告知过年人太多只能一个安排在18楼，一个安排在5楼，我仔细看订单我定的应该是18到21楼！而且5楼明显和18楼的房间不一样！可气的是办理的前台小哥是不是觉得北方人好糊弄，给我们的房号1847和524，恨不得把不好的房号和房间都安排给我们，因为比较晚了而且带着老人孩子，大过年的也就没有在争论。不会再去了！', '2023-01-29', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028068e3c98b0941765dbd', '交通很便利，酒店旁边吃喝玩乐都齐全。春节带家人入住的，大堂里很热闹，浓郁的岭南风情。逛了一圈，是名副其实的花园酒店，房间很大也整洁。特别夸一夸酒店的服务??，因为临走前想吃一回荔湾亭，经理特意帮我们排号，这一趟旅程非常完美。', '["https://dimg04.c-ctrip.com/images/0230w12000am8ql1h8322_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000am91zhq5337_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000am8qien30A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-07', '红棉大床套房', '套房', '家庭亲子', 112, 4.727387818712341, 0, 0.0, 7, 2.079441541679836, 9, '["交通便利性", "周边配套", "整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '交通很便利，酒店旁边吃喝玩乐都齐全。春节带家人入住的，大堂里很热闹，浓郁的岭南风', '交通很便利，酒店旁边吃喝玩乐都齐全。春节带家人入住的，大堂里很热闹，浓郁的岭南风情。逛了一圈，是名副其实的花园酒店，房间很大也整洁。特别夸一夸酒店的服务??，因为临走前想吃一回荔湾亭，经理特意帮我们排号，这一趟旅程非常完美。', '2023-02-07', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dbe', '金卡会员，办入住的时候说高一级别的房型没房不能升级了，然后我问那加钱可不可以，说可以，然后我就说那既然加钱可以升那说明有空房，有空房为什么不能升房？于是说去确认，回来就说满房了，只剩套房，需要补差价1000多。会员赠送早餐只赠送一份，我说那既然升房没有享受早餐不可以多送一份吗？回答不可以，OK，反正后来也没去过行政酒廊了。房间内只放了两瓶水，第一晚打电话让送水和冰块等了很久都没送，再次打电话之后直到睡觉都没有送来，前后等了差不多有一两个小时……第二天打扫卫生非常敷衍，衣物就这样没有叠好直接塞在枕头中间……孩子小尿尿不小心尿到地上，我们自己简单擦了下，但保洁打扫的时候也没有清理干净，总是能闻到味儿??', '["https://dimg04.c-ctrip.com/images/0236u12000ahysjkc7934_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-01-24', '花园大床房', '大床房', '家庭亲子', 303, 5.717027701406222, 3, 1.3862943611198906, 2, 1.0986122886681098, 9, '["前台服务", "客房服务", "卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '金卡会员，办入住的时候说高一级别的房型没房不能升级了，然后我问那加钱可不可以，说', '金卡会员，办入住的时候说高一级别的房型没房不能升级了，然后我问那加钱可不可以，说可以，然后我就说那既然加钱可以升那说明有空房，有空房为什么不能升房？于是说去确认，回来就说满房了，只剩套房，需要补差价1000多。会员赠送早餐只赠送一份，我说那既然升房没有享受早餐不可以多送一份吗？回答不可以，OK，反正后来也没去过行政酒廊了。房间内只放了两瓶水，第一晚打电话让送水和冰块等了很久都没送，再次打电话之后直到睡觉都没有送来，前后等了差不多有一两个小时……第二天打扫卫生非常敷衍，衣物就这样没有叠好直接塞在枕头中间……孩子小尿尿不小心尿到地上，我们自己简单擦了下，但保洁打扫的时候也没有清理干净，总是能闻到味儿??', '2023-01-24', 2, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dbf', '选了好久，最终还是选择了花园酒店，出门右边就是地铁，去哪里都很方便！从进门门童开始，可以感觉到工作人员很热情，进大厅就看见漂亮的装饰树，虽然人多，服务人员很好，总体给人很温馨的感觉，下次有机会去广州还是会选择他们！白金五星级酒店确实是实至名归！', '["https://dimg04.c-ctrip.com/images/0232e12000aiv585w1A10_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000aiv5a91C3AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000aiv5m2d6980_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000aiv56vbC9B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-28', '城央绿意大床房', '大床房', '家庭亲子', 122, 4.812184355372417, 0, 0.0, 5, 1.791759469228055, 8, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '选了好久，最终还是选择了花园酒店，出门右边就是地铁，去哪里都很方便！从进门门童开', '选了好久，最终还是选择了花园酒店，出门右边就是地铁，去哪里都很方便！从进门门童开始，可以感觉到工作人员很热情，进大厅就看见漂亮的装饰树，虽然人多，服务人员很好，总体给人很温馨的感觉，下次有机会去广州还是会选择他们！白金五星级酒店确实是实至名归！', '2023-01-28', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc0', '酒店大堂很大气，服务不错。生意较好前台四个接待火力全开也是要排一会队办入住的，地理位置很不错，5号线淘金地铁站上来就是，对过广州酒家，侧面点都德', '["https://dimg04.c-ctrip.com/images/0232412000aqnbtg9414C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000aqnbvvoD554_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230r12000aqnbrkq2A69_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000aqnbtgn4AB2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000aqnbtzj3459_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-05', '红棉大床套房', '套房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 15, 2.772588722239781, 7, '["交通便利性", "周边配套", "退房/入住效率"]'::jsonb, '交通便利性', '周边配套', '退房/入住效率', '未知酒店', '未知地点', '匿名', '酒店大堂很大气，服务不错。生意较好前台四个接待火力全开也是要排一会队办入住的，地', '酒店大堂很大气，服务不错。生意较好前台四个接待火力全开也是要排一会队办入住的，地理位置很不错，5号线淘金地铁站上来就是，对过广州酒家，侧面点都德', '2023-03-05', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc1', '一个改革开放第一批的五星级酒店，历经40年，能保持这样的状况实在难得，各项硬件还是很不错，继续加油！软件方面也很好，这次前台的吴灵伶小姐，漂亮又可爱，关键是服务态度超好，热心主动帮助客人解决问题，工作效率很高，非常熟悉各项流程，让客人感觉很舒服。本人从事服务行业的管理工作数十年，像灵伶这样的员工实在是难得，是企业宝贵的资产。', '["https://dimg04.c-ctrip.com/images/0230812000f1f4dpdACB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000f1f4oin98FB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-07', '花园大床房', '大床房', '其他', 163, 5.099866427824199, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '一个改革开放第一批的五星级酒店，历经40年，能保持这样的状况实在难得，各项硬件还', '一个改革开放第一批的五星级酒店，历经40年，能保持这样的状况实在难得，各项硬件还是很不错，继续加油！软件方面也很好，这次前台的吴灵伶小姐，漂亮又可爱，关键是服务态度超好，热心主动帮助客人解决问题，工作效率很高，非常熟悉各项流程，让客人感觉很舒服。本人从事服务行业的管理工作数十年，像灵伶这样的员工实在是难得，是企业宝贵的资产。', '2024-08-07', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc2', '春节广州到处爆满，选择了花园，虽然做好了老酒店的面积是硬伤的准备，但是这家是1.3的床，对带孩子的相对友好，订的是绿意双床。给后面订房的提个醒，1、这个房型的的淋浴必须跨进一个正方形的小浴缸，台阶很高，对小朋友和老人非常不友好。也不安全，不是常规的走入淋浴！！！2.房间不算很旧，但是墙上的插座很多都不好用，床头的那个时钟我住了3天一直7点08！
3.前台的接待办入住也非常的慢！而且没有服务意识和亲和力，一个劲强调需要给他空间！空间！说他墨迹他说嗯，我们是小地方确实慢！广州的是小地方？这是粉刺内含谁呢？
3酒店的瀑布餐厅早餐也不好吃。
4.一楼大堂没有休息区。每次进出酒店大堂都乱哄哄的！
5.周边有广州酒家，利苑，还有其他餐饮选项，如果不赶时间真的不要吃酒店那早餐。。。
6、周边在修地铁去利苑宜安广场需要绕小道步行不远5分钟即可。', '["https://dimg04.c-ctrip.com/images/0231112000aik10ip054E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000aijyuvi4DB0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000aik22mz1FD9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000aik1q4a9DE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-01-26', '城央绿意双床房', '双床房', '家庭亲子', 369, 5.91350300563827, 2, 1.0986122886681098, 1, 0.6931471805599453, 9, '["房间设施", "前台服务", "餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '春节广州到处爆满，选择了花园，虽然做好了老酒店的面积是硬伤的准备，但是这家是1.', '春节广州到处爆满，选择了花园，虽然做好了老酒店的面积是硬伤的准备，但是这家是1.3的床，对带孩子的相对友好，订的是绿意双床。给后面订房的提个醒，1、这个房型的的淋浴必须跨进一个正方形的小浴缸，台阶很高，对小朋友和老人非常不友好。也不安全，不是常规的走入淋浴！！！2.房间不算很旧，但是墙上的插座很多都不好用，床头的那个时钟我住了3天一直7点08！
3.前台的接待办入住也非常的慢！而且没有服务意识和亲和力，一个劲强调需要给他空间！空间！说他墨迹他说嗯，我们是小地方确实慢！广州的是小地方？这是粉刺内含谁呢？
3酒店的瀑布餐厅早餐也不好吃。
4.一楼大堂没有休息区。每次进出酒店大堂都乱哄哄的！
5.周边有广州酒家，利苑，还有其他餐饮选项，如果不赶时间真的不要吃酒店那早餐。。。
6、周边在修地铁去利苑宜安广场需要绕小道步行不远5分钟即可。', '2023-01-26', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc3', '来广州很多次了，第一次入住花园酒店却是因一座有博物馆的酒店，整体感觉非常好。地理位置好，大堂富丽堂皇，干净卫生，早餐丰盛。当然最值得一提是博物馆啦！附照如下！！！', '["https://dimg04.c-ctrip.com/images/0234j12000asxg2s39FC5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000asx4jo0F069_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000asxhlua5D17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231r12000asxhz7mF6EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000asx4e0u3E46_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000asx5nbf1906_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000asx5j0gF0AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000asx4sgvA93C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-23', '红棉大床套房', '套房', '家庭亲子', 81, 4.406719247264253, 0, 0.0, 4, 1.6094379124341005, 7, '["整体满意度", "周边配套", "卫生状况"]'::jsonb, '整体满意度', '周边配套', '卫生状况', '未知酒店', '未知地点', '匿名', '来广州很多次了，第一次入住花园酒店却是因一座有博物馆的酒店，整体感觉非常好。地理', '来广州很多次了，第一次入住花园酒店却是因一座有博物馆的酒店，整体感觉非常好。地理位置好，大堂富丽堂皇，干净卫生，早餐丰盛。当然最值得一提是博物馆啦！附照如下！！！', '2023-03-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc4', '天呐花园酒店可以说是我住过服务最好的酒店！国内外也住过很多五星，而且都是国际连锁酒店，但没遇到过比花园服务更好的！！因为我入住时房间有一点异味，前前后后给我打了三次回访电话，第一天就搬来了两台空气净化器，其实在我出去的几个小时里房间已经完全没味道了，酒店还送了我糖和水果。第二天打电话问我是否处理好，还说要送我一个礼物（礼物超级喜欢！谢谢！简直就是猜到我想要什么了），客房服务接电话态度、酒店大堂等工作人员态度都超级好。名副其实宾至如归，以后来广州还住这里！而且位置超级好是我喜欢的老城区，很有老广味道楼下还有很多很多美食。一定会推荐给朋友的', '["https://dimg04.c-ctrip.com/images/0234t12000ai220dkDC7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000ai221zj927C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000ai23i432D99_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000ai23ei6B1EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-24', '花园大床房', '大床房', '情侣出游', 271, 5.605802066295998, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '天呐花园酒店可以说是我住过服务最好的酒店！国内外也住过很多五星，而且都是国际连锁', '天呐花园酒店可以说是我住过服务最好的酒店！国内外也住过很多五星，而且都是国际连锁酒店，但没遇到过比花园服务更好的！！因为我入住时房间有一点异味，前前后后给我打了三次回访电话，第一天就搬来了两台空气净化器，其实在我出去的几个小时里房间已经完全没味道了，酒店还送了我糖和水果。第二天打电话问我是否处理好，还说要送我一个礼物（礼物超级喜欢！谢谢！简直就是猜到我想要什么了），客房服务接电话态度、酒店大堂等工作人员态度都超级好。名副其实宾至如归，以后来广州还住这里！而且位置超级好是我喜欢的老城区，很有老广味道楼下还有很多很多美食。一定会推荐给朋友的', '2023-01-24', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc5', '广州行最后一天（也是除夕这天）入住广州花园
酒店整体新年氛围拉满 各种新春活动
提前两天就有来电确认行程和需求
楼上设置的酒店博物馆 很有情怀（反正很戳我啦）
