INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc6', '很庆幸春节期间选择了这家酒店，十足的年味，整个大堂都充满了节日的喜庆，酒店做足了功夫，小朋友们都特别喜欢在大堂里玩，大年初一的早上还在酒店门口和大堂里看到了正宗的舞龙舞狮表演，酒店内部还有一个花园，瀑布，周边吃饭也很便利，点都德和广州酒家步行可达，门口就有地铁，出行也很方便。老牌酒店，精于管理，是不可多得的好选择。', '["https://dimg04.c-ctrip.com/images/0230c12000amkcfsn1D69_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000amkcph3C59A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-08', '城央绿意双床房', '双床房', '朋友出游', 158, 5.068904202220232, 0, 0.0, 14, 2.70805020110221, 9, '["整体满意度", "周边配套", "交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性', '未知酒店', '未知地点', '匿名', '很庆幸春节期间选择了这家酒店，十足的年味，整个大堂都充满了节日的喜庆，酒店做足了', '很庆幸春节期间选择了这家酒店，十足的年味，整个大堂都充满了节日的喜庆，酒店做足了功夫，小朋友们都特别喜欢在大堂里玩，大年初一的早上还在酒店门口和大堂里看到了正宗的舞龙舞狮表演，酒店内部还有一个花园，瀑布，周边吃饭也很便利，点都德和广州酒家步行可达，门口就有地铁，出行也很方便。老牌酒店，精于管理，是不可多得的好选择。', '2023-02-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028073e3c98b0941765dc7', '元宵节前特意坐高铁从深圳来到广州入住花园酒店。去年10月中旬入住时对酒店的行政酒廊体验很好，所以这次特意选择了可享用行政酒廊的大床房3晚。入住办理、出入开门、行李存放等服务都很到位。大床房内饰、床寝用品、卫生洗浴等设施都令人舒适应手。不巧的是浴室的下水道不很通畅。中午洗澡后流水满地，尽管浴房玻璃门外有地垫，但水还是流到了卫生间和门廊。我们午休1个多小时后积水仍在。如果只住一晚将就一下算了，可是要连住3晚，万一滑倒了周围不是玻璃就是浴缸，地面又是大理石，都不是一件小事，可谓有严重的安全隐患。于是把地面两处的积水拍照后去大堂前台商量能否换一间房。令我想不到的是大堂经理YANNIS范认真耐心听取了我的诉求，留存了我出示的两处积水的照片，很快同意并落实了换房。我们被免费换到了楼层更高，设施更优，面积更大的红棉大床套房。真的被YANNIS范经理的至真至诚的处理结果暖心和感动到了。在此，为她的处理偶发事件的能力、水平和智慧点赞！也为她的果断、魄力和大气格局点赞！再次感谢YANNIS范经理！酒店行政酒廊的早餐、下午茶、欢乐时光的出品、环境、服务一如既往的好。特别点赞早餐。自助+点单、即点即做的模式与上海的J酒店上海中心的早餐模式一样一样，真的令我惊喜和满意。中西式早餐出品比瀑布餐厅的全自助早餐精致优质很多。说实话，行政酒廊的早餐优于自助早餐在酒店行业很少见。我们3天的早餐后面两天都选择了行政酒廊。印度藉服务员CARRIE中文讲得好，服务很主动很勤快很热情很nice。元宵节那天酒店早餐没有汤圆，行政酒廊的欢乐时光也没汤圆，我在向CARRIE询问时随口说了一句：特意来花园酒店过元宵节，没想到在酒店吃汤圆反而成了一种奢望。不一会CARRIE送上来两盅红豆沙芝麻汤圆，真的令我们很惊喜。CARRIE说她和同事把我们的询问和需求反馈到了酒店中餐厅，那里特意为我们做了这两碗汤圆。我和先生听了都非常非常感动。在此，特别感谢中餐厅的后厨师傅，谢谢！辛苦了！也特别感谢印度藉服务员CARRIE，谢谢你的用心和勤快！你们的优质服务让我们度过了一个很美好又难忘的元宵节。细节决定未来，服务决定高度。服务的灵魂是真诚。花园酒店注重细节服务真诚，非常值得入住体验。强烈推荐！', '["https://dimg04.c-ctrip.com/images/0231q12000amss00nCADE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000amsq1lo1FDA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000amssv01BB38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000amskyf82A52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000amsxozz6A36_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000amsnuda87C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000amszxv28641_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235l12000amszxv30716_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000amt9c6p9DFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-09', '花园大床房', '大床房', '情侣出游', 930, 6.836259277277067, 0, 0.0, 100, 4.61512051684126, 10, '["前台服务", "餐饮设施", "房间设施"]'::jsonb, '前台服务', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '元宵节前特意坐高铁从深圳来到广州入住花园酒店。去年10月中旬入住时对酒店的行政酒', '元宵节前特意坐高铁从深圳来到广州入住花园酒店。去年10月中旬入住时对酒店的行政酒廊体验很好，所以这次特意选择了可享用行政酒廊的大床房3晚。入住办理、出入开门、行李存放等服务都很到位。大床房内饰、床寝用品、卫生洗浴等设施都令人舒适应手。不巧的是浴室的下水道不很通畅。中午洗澡后流水满地，尽管浴房玻璃门外有地垫，但水还是流到了卫生间和门廊。我们午休1个多小时后积水仍在。如果只住一晚将就一下算了，可是要连住3晚，万一滑倒了周围不是玻璃就是浴缸，地面又是大理石，都不是一件小事，可谓有严重的安全隐患。于是把地面两处的积水拍照后去大堂前台商量能否换一间房。令我想不到的是大堂经理YANNIS范认真耐心听取了我的诉求，留存了我出示的两处积水的照片，很快同意并落实了换房。我们被免费换到了楼层更高，设施更优，面积更大的红棉大床套房。真的被YANNIS范经理的至真至诚的处理结果暖心和感动到了。在此，为她的处理偶发事件的能力、水平和智慧点赞！也为她的果断、魄力和大气格局点赞！再次感谢YANNIS范经理！酒店行政酒廊的早餐、下午茶、欢乐时光的出品、环境、服务一如既往的好。特别点赞早餐。自助+点单、即点即做的模式与上海的J酒店上海中心的早餐模式一样一样，真的令我惊喜和满意。中西式早餐出品比瀑布餐厅的全自助早餐精致优质很多。说实话，行政酒廊的早餐优于自助早餐在酒店行业很少见。我们3天的早餐后面两天都选择了行政酒廊。印度藉服务员CARRIE中文讲得好，服务很主动很勤快很热情很nice。元宵节那天酒店早餐没有汤圆，行政酒廊的欢乐时光也没汤圆，我在向CARRIE询问时随口说了一句：特意来花园酒店过元宵节，没想到在酒店吃汤圆反而成了一种奢望。不一会CARRIE送上来两盅红豆沙芝麻汤圆，真的令我们很惊喜。CARRIE说她和同事把我们的询问和需求反馈到了酒店中餐厅，那里特意为我们做了这两碗汤圆。我和先生听了都非常非常感动。在此，特别感谢中餐厅的后厨师傅，谢谢！辛苦了！也特别感谢印度藉服务员CARRIE，谢谢你的用心和勤快！你们的优质服务让我们度过了一个很美好又难忘的元宵节。细节决定未来，服务决定高度。服务的灵魂是真诚。花园酒店注重细节服务真诚，非常值得入住体验。强烈推荐！', '2023-02-09', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dc8', '春节渡假全家打卡白金五星，连住四晚总体失望，不会再来。房间与快捷酒店同一档次。大堂乱糟糟的有壁画给个四星吧。后花园终于有五星的感觉。春节来也不能要求太高，前厅部与餐饮部很热情。客房部感觉人手不够。礼宾部冷漠，门外的门童直接摆烂，建议调去客房部。对携程铂金没有任何礼遇，春节不差携程这点客流吧。', '["https://dimg04.c-ctrip.com/images/0234g12000aikisn19179_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000aikizb09918_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-01-26', '花园双床房', '双床房', '家庭亲子', 146, 4.990432586778736, 0, 0.0, 5, 1.791759469228055, 8, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '春节渡假全家打卡白金五星，连住四晚总体失望，不会再来。房间与快捷酒店同一档次。大', '春节渡假全家打卡白金五星，连住四晚总体失望，不会再来。房间与快捷酒店同一档次。大堂乱糟糟的有壁画给个四星吧。后花园终于有五星的感觉。春节来也不能要求太高，前厅部与餐饮部很热情。客房部感觉人手不够。礼宾部冷漠，门外的门童直接摆烂，建议调去客房部。对携程铂金没有任何礼遇，春节不差携程这点客流吧。', '2023-01-26', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dc9', '来之前是先预定的白天鹅，抱着电话咨询下的想法联系了花园酒店，没想到一个电话让我退掉了白天鹅入住花园酒店，事后觉得自己非常英明！从电话预定到入住直到离店，所有的过程都非常完美，哪怕是春节期间细节都做得非常好，从进酒店一刻感受就是宾至如归，清理阿姨态度尤其好，没有评论说的不多给水的事情，只会多给你！总之非常完美，下次还要入住', '["https://dimg04.c-ctrip.com/images/0237012000ai9c6w9DCC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000ai9d05z5F1C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-25', '红棉大床套房', '套房', '家庭亲子', 161, 5.087596335232384, 0, 0.0, 28, 3.367295829986474, 8, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '来之前是先预定的白天鹅，抱着电话咨询下的想法联系了花园酒店，没想到一个电话让我退', '来之前是先预定的白天鹅，抱着电话咨询下的想法联系了花园酒店，没想到一个电话让我退掉了白天鹅入住花园酒店，事后觉得自己非常英明！从电话预定到入住直到离店，所有的过程都非常完美，哪怕是春节期间细节都做得非常好，从进酒店一刻感受就是宾至如归，清理阿姨态度尤其好，没有评论说的不多给水的事情，只会多给你！总之非常完美，下次还要入住', '2023-01-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dca', '愉快的入住＆用餐体验，不愧是白金五星级的花园酒店~前台Joyce和Cecilia服务态度好好哦，给的小羊和冰箱贴可可爱爱，无论是check in还是咨询都是亲切又有耐心?? 路上遇到Patrick，指引很到位??总机Dany还有Lydia声音温柔极了，好好听~最后遇到的粉色小姐姐Rain，快捷退房太太太方便啦~', '["https://dimg04.c-ctrip.com/images/0236s12000br43ti530F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000br3wcglBCD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000br482r44BCA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000br3wxvc3AA1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000br3x6xeAB83_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000br45lb1A5FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-26', '花园大床房', '大床房', '家庭亲子', 156, 5.056245805348308, 0, 0.0, 8, 2.19722457733622, 9, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '愉快的入住＆用餐体验，不愧是白金五星级的花园酒店~前台Joyce和Cecilia', '愉快的入住＆用餐体验，不愧是白金五星级的花园酒店~前台Joyce和Cecilia服务态度好好哦，给的小羊和冰箱贴可可爱爱，无论是check in还是咨询都是亲切又有耐心?? 路上遇到Patrick，指引很到位??总机Dany还有Lydia声音温柔极了，好好听~最后遇到的粉色小姐姐Rain，快捷退房太太太方便啦~', '2023-07-26', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dcb', '这次出行的惊喜，是花园酒店给的
设施：应该是刚装修不久，整个酒店看起来还很新。能免费停车，酒店的游泳池和健身房的设施也不错
卫生：每天上午打扫很及时。
环境：春节的氛围感简直不能更赞了，大年初一还有舞龙舞狮表演
