INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dcc', '老牌五星酒店，花园真的很美。服务人员都很热情，办理入住时TONY MAI 很周到，看到带着小孩，会体贴的送上小饼干，孩子很开心。', '["https://dimg04.c-ctrip.com/images/0232z12000arxfp0aB44A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000arxa4qc7155_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-15', '花园大床房', '大床房', '家庭亲子', 64, 4.174387269895637, 0, 0.0, 5, 1.791759469228055, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '老牌五星酒店，花园真的很美。服务人员都很热情，办理入住时TONY MAI 很周到', '老牌五星酒店，花园真的很美。服务人员都很热情，办理入住时TONY MAI 很周到，看到带着小孩，会体贴的送上小饼干，孩子很开心。', '2023-03-15', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dcd', '服务非常好，不愧是老牌酒店；春节期间入住，大堂每天都有各种吸引小朋友的表演，最爱小丑表演，对小朋友很有爱；房间有点局促，但是该有的设施都一应俱全，客房服务非常温馨，一点点小建议，退房能否给个快速通道，和入住客人一起排队很慢，中间还有插队办理的，这方面管理有待提高。', '["https://dimg04.c-ctrip.com/images/0230v12000aiozsphBAA5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000aioyo1r6459_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000aioyer91CEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-27', '花园大床房', '大床房', '家庭亲子', 132, 4.890349128221754, 0, 0.0, 8, 2.19722457733622, 9, '["前台服务", "退房/入住效率", "客房服务"]'::jsonb, '前台服务', '退房/入住效率', '客房服务', '未知酒店', '未知地点', '匿名', '服务非常好，不愧是老牌酒店；春节期间入住，大堂每天都有各种吸引小朋友的表演，最爱', '服务非常好，不愧是老牌酒店；春节期间入住，大堂每天都有各种吸引小朋友的表演，最爱小丑表演，对小朋友很有爱；房间有点局促，但是该有的设施都一应俱全，客房服务非常温馨，一点点小建议，退房能否给个快速通道，和入住客人一起排队很慢，中间还有插队办理的，这方面管理有待提高。', '2023-01-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dce', '非常喜欢的', '["https://dimg04.c-ctrip.com/images/0232x12000bm6wvbj7176_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-09', '花园双床房', '双床房', '商务出差', 5, 1.791759469228055, 0, 0.0, 7, 2.079441541679836, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '非常喜欢的', '非常喜欢的', '2023-07-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dcf', '带爸妈来广州过年，入住花园酒店。第一眼有被酒店大堂惊艳到，背景墙上的红楼梦人物图金碧辉煌，衬着火树银花相当气派且有氛围。我们订了三间房，个人感觉红棉大床房性价比最高，面积也很合理。小套房设计孩子睡觉不会被打扰，二米床适合三口之家。淋浴浴缸都有。虽然设备有些老旧但总体住的还是很舒适的。酒店就在五号线淘金站出口，对面就是友谊商城，广州酒家（有个地道可以过，不用走天桥）。进出非常方便。酒店的服务也很好，工作人员都很热情。是这次很愉快的住宿体验。建议: 换床单被套，和换浴巾可以分开选择。我不需要每天更换床品，但用过的浴巾需要更换一下，但感觉只能全换，或者全不换。马桶间缺一个可以放手机的架子。', '["https://dimg04.c-ctrip.com/images/0233e12000aike4r4A705_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000aikdoi31C99_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000aikejc1A147_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000aikdq7m20F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-26', '花园双床房', '双床房', '家庭亲子', 295, 5.69035945432406, 0, 0.0, 3, 1.3862943611198906, 9, '["性价比", "交通便利性", "整体满意度"]'::jsonb, '性价比', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '带爸妈来广州过年，入住花园酒店。第一眼有被酒店大堂惊艳到，背景墙上的红楼梦人物图', '带爸妈来广州过年，入住花园酒店。第一眼有被酒店大堂惊艳到，背景墙上的红楼梦人物图金碧辉煌，衬着火树银花相当气派且有氛围。我们订了三间房，个人感觉红棉大床房性价比最高，面积也很合理。小套房设计孩子睡觉不会被打扰，二米床适合三口之家。淋浴浴缸都有。虽然设备有些老旧但总体住的还是很舒适的。酒店就在五号线淘金站出口，对面就是友谊商城，广州酒家（有个地道可以过，不用走天桥）。进出非常方便。酒店的服务也很好，工作人员都很热情。是这次很愉快的住宿体验。建议: 换床单被套，和换浴巾可以分开选择。我不需要每天更换床品，但用过的浴巾需要更换一下，但感觉只能全换，或者全不换。马桶间缺一个可以放手机的架子。', '2023-01-26', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dd0', '花园酒店是老牌的广州五星级酒店，对它还是充满了期待，但入住后发现浴室毯子上明显的一戳头发没有打扫掉，卫生间的边角还有抽屉里都有散落的头发没有打扫干净，对于细节上的处理还是比较失望。酒店的花园是亮点，服务也没啥问题，在酒店荔湾亭吃了中饭感觉也不错值得一去。这次春节假期，酒店在年初一还搞了醒狮活动，非常棒，让我们体验了岭南文化和广州过年热闹的节日气氛。希望酒店能在细节上更完善，毕竟细节才是真正体现酒店的管理和质量！', '["https://dimg04.c-ctrip.com/images/0234i12000aiqey6rAD2D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000aiqgx8lAAC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000aiqf59573FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-01-27', '花园大床房', '大床房', '朋友出游', 207, 5.337538079701318, 0, 0.0, 6, 1.9459101490553128, 9, '["卫生状况", "整体满意度", "餐饮设施"]'::jsonb, '卫生状况', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店是老牌的广州五星级酒店，对它还是充满了期待，但入住后发现浴室毯子上明显的', '花园酒店是老牌的广州五星级酒店，对它还是充满了期待，但入住后发现浴室毯子上明显的一戳头发没有打扫掉，卫生间的边角还有抽屉里都有散落的头发没有打扫干净，对于细节上的处理还是比较失望。酒店的花园是亮点，服务也没啥问题，在酒店荔湾亭吃了中饭感觉也不错值得一去。这次春节假期，酒店在年初一还搞了醒狮活动，非常棒，让我们体验了岭南文化和广州过年热闹的节日气氛。希望酒店能在细节上更完善，毕竟细节才是真正体现酒店的管理和质量！', '2023-01-27', 4, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028080e3c98b0941765dd1', '很意外的收获！特别满意的一次入住，酒店前台的帅哥Billy很客气的帮忙升级了房型，广州历史悠久的大酒店，没有一点陈旧的感觉，干净卫生！这次是晚上入住，一大早就退房了，没来得及体验餐厅的美食和后花园的美景。', '["https://dimg04.c-ctrip.com/images/0230112000apcvhpb6341_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000apcv3ms62D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i12000apck134BA76_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000apcol2h4AE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000apcuv0pBA88_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000apctrqj75C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-23', '花园大床房', '大床房', '独自旅行', 102, 4.634728988229636, 0, 0.0, 7, 2.079441541679836, 8, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '很意外的收获！特别满意的一次入住，酒店前台的帅哥Billy很客气的帮忙升级了房型', '很意外的收获！特别满意的一次入住，酒店前台的帅哥Billy很客气的帮忙升级了房型，广州历史悠久的大酒店，没有一点陈旧的感觉，干净卫生！这次是晚上入住，一大早就退房了，没来得及体验餐厅的美食和后花园的美景。', '2023-02-23', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802808ae3c98b0941765dd2', '地段不错，出行方便。后花园环境值得观赏。整个酒店服务算中等。不方便的地方有两个，一是停车每次出场均要和礼宾部说，二是作为南方的星级酒店，客房里长供两瓶350ml矿泉水，是不是有点少了，虽然每次找前台要，都能很快送来，是不是可以综合记录下客人需要，以便精准服务，提升体验。', '["https://dimg04.c-ctrip.com/images/0232y12000aiild58E09F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000aiin5cbF3DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-01-26', '城央绿意双床房', '双床房', '家庭亲子', 135, 4.912654885736052, 0, 0.0, 4, 1.6094379124341005, 8, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '地段不错，出行方便。后花园环境值得观赏。整个酒店服务算中等。不方便的地方有两个，', '地段不错，出行方便。后花园环境值得观赏。整个酒店服务算中等。不方便的地方有两个，一是停车每次出场均要和礼宾部说，二是作为南方的星级酒店，客房里长供两瓶350ml矿泉水，是不是有点少了，虽然每次找前台要，都能很快送来，是不是可以综合记录下客人需要，以便精准服务，提升体验。', '2023-01-26', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802808ae3c98b0941765dd3', '优点：环境好，服务有好有坏吧，整体还不错
缺点：1，设施老化严重，房间内老旧，衣柜换了2房间还是关不严，导致衣柜灯光一直亮很恐怖，总感觉会出来咒怨。2，荔弯亭前台接待，地域歧视，对北方人态度特别差，不仅丑而且说话也不好听，真想骂她。', '["https://dimg04.c-ctrip.com/images/0236612000ahle1br3D57_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-01-22', '花园双床房', '双床房', '家庭亲子', 116, 4.762173934797756, 5, 1.791759469228055, 5, 1.791759469228055, 7, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '优点：环境好，服务有好有坏吧，整体还不错', '优点：环境好，服务有好有坏吧，整体还不错
缺点：1，设施老化严重，房间内老旧，衣柜换了2房间还是关不严，导致衣柜灯光一直亮很恐怖，总感觉会出来咒怨。2，荔弯亭前台接待，地域歧视，对北方人态度特别差，不仅丑而且说话也不好听，真想骂她。', '2023-01-22', 2, '房间设施');
