INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802808ae3c98b0941765dd6', '隔了37年再次入住花园酒店，往事历历在目，感谢花园的花园还在，假山瀑布依旧，看到跑来跑去的孩子们的笑脸，和当年的自己重叠。祝愿酒店历久弥新，带着岁月的庄重和沉淀，永远保持年轻，永远进步。', '["https://dimg04.c-ctrip.com/images/0232s12000aj8cen62283_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000aj8at2079C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000aj89a9yB220_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000aj8etgz6DD5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-29', '花园双床房', '双床房', '家庭亲子', 93, 4.543294782270004, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '隔了37年再次入住花园酒店，往事历历在目，感谢花园的花园还在，假山瀑布依旧，看到', '隔了37年再次入住花园酒店，往事历历在目，感谢花园的花园还在，假山瀑布依旧，看到跑来跑去的孩子们的笑脸，和当年的自己重叠。祝愿酒店历久弥新，带着岁月的庄重和沉淀，永远保持年轻，永远进步。', '2023-01-29', 5, '整体满意度');
