INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802808ae3c98b0941765ddb', '前厅何小姐服务非常好！酒店环境也很不错，非常适合一家出行居住！', '["https://dimg04.c-ctrip.com/images/0230r12000ekitod46797_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000ekiwalhFC3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000ekj077k4648_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000ekixn2v90AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-25', '红棉大床套房', '套房', '情侣出游', 31, 3.4657359027997265, 0, 0.0, 1, 0.6931471805599453, 5, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '前厅何小姐服务非常好！酒店环境也很不错，非常适合一家出行居住！', '前厅何小姐服务非常好！酒店环境也很不错，非常适合一家出行居住！', '2024-06-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028095e3c98b0941765ddc', '度周末再次选择大羊城 是因为花园酒店
先不说花园酒店是中国唯三的白金五星级饭店 也不说花园酒店是世界知名建筑设计师设计 前国家主席奠基 第二代领导核心题名等这些皇冠 这些光环在我看来 跟大家喜欢的只是奥运冠军 而不是喜欢这个运动本身一样的道理 所以 我不想说
这次我想说一下我对于酒店的个人见解
在传统观念当中 酒店只是我们到另外一个城市需要晚上住宿的地方 随着我的出行越来越多 具有精准定位 独立设计 独具匠心 具有内涵 体验美好的酒店也慢慢成为了我的目的地之一
这些酒店所散发出来的吸引力不仅仅是一种对于酒店或者旅行的情怀 更多的是渗透于生活当中的延绵沉淀 现在已经慢慢成为我的一种生活方式 简单点说 就是吃美食 耍酒店
关于花园酒店建筑本身的一点思考
花园酒店是贝聿铭先森指导的 贝先森是美国宾夕法尼亚大学建筑学毕业 作为华人的贝先森在中国有很高的知名度 我见过贝先森的作品 例如香港????中银大厦 但我还没去过法国巴黎卢浮宫 花园酒店在差不多四十年前就建造完成 今天仍然洋气 理念仍然先进 细节仍然到位 在其作品中体现得淋漓尽致 其实本质就是更早的接触了现代文明', '["https://dimg04.c-ctrip.com/images/0232c12000ajqlic1EA88_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000ajqnhct9566_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000ajqllq10666_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-31', '粤韵大床套房', '套房', '家庭亲子', 486, 6.18826412308259, 0, 0.0, 38, 3.6635616461296463, 9, '["整体满意度", "房间设施", "公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '度周末再次选择大羊城 是因为花园酒店', '度周末再次选择大羊城 是因为花园酒店
