INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028095e3c98b0941765dde', '老牌的五星级酒店，设施有些年头了，办入住给免费升级了套房。还免费加了一个床。马桶声音有点大，卫生有带提高。酒店的床垫是很舒服值得入睡的，在携程定的双早，到行政酒廊用早餐说服务员说只有一位，瞬间心情就不太好，最后沟通还是去吃了早餐的，早餐种类较少，味道还可以。水果nice、尤其是蓝莓很好??。不明白酒店内部的各个部门有什么问题没有沟通好。原本还打算周六继续订房住的。现在还在还在纠结中….', '["https://dimg04.c-ctrip.com/images/0206m12000aff3juoE325_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0203512000aff2yln7117_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0203a12000aff3n8b12F5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-01-12', '花园双床房', '双床房', '商务出差', 194, 5.272999558563747, 1, 0.6931471805599453, 61, 4.127134385045092, 7, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌的五星级酒店，设施有些年头了，办入住给免费升级了套房。还免费加了一个床。马桶', '老牌的五星级酒店，设施有些年头了，办入住给免费升级了套房。还免费加了一个床。马桶声音有点大，卫生有带提高。酒店的床垫是很舒服值得入睡的，在携程定的双早，到行政酒廊用早餐说服务员说只有一位，瞬间心情就不太好，最后沟通还是去吃了早餐的，早餐种类较少，味道还可以。水果nice、尤其是蓝莓很好??。不明白酒店内部的各个部门有什么问题没有沟通好。原本还打算周六继续订房住的。现在还在还在纠结中….', '2023-01-12', 4, '房间设施');
