INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028095e3c98b0941765de5', '又来花园小住，放开后的花园酒店又恢复了往昔的繁荣，有人气多了，希望新一年越来越好。
