INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280a1e3c98b0941765dec', 'kiki Kristy 服务很好，酒店环境不错，推荐推荐！', '["https://dimg04.c-ctrip.com/images/0230p12000b58nl96C47E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-03', '羊羊得意主题大床房', '主题房', '家庭亲子', 29, 3.4011973816621555, 0, 0.0, 4, 1.6094379124341005, 4, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', 'kiki Kristy 服务很好，酒店环境不错，推荐推荐！', 'kiki Kristy 服务很好，酒店环境不错，推荐推荐！', '2023-05-03', 5, '前台服务');
