INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280a1e3c98b0941765dee', '不愧为中国三大白金级酒店之一，环境优美，有花园和博物馆可以参观，服务热情贴心，早餐丰盛美味，除了床有些软，住感几乎完美。', '["https://dimg04.c-ctrip.com/images/0236712000ar94dz5FF9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000ar8oqmf5573_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000ar8sd3n62B5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000ar92kna1500_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-09', '城央绿意双床房', '双床房', '朋友出游', 60, 4.110873864173311, 0, 0.0, 6, 1.9459101490553128, 9, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '不愧为中国三大白金级酒店之一，环境优美，有花园和博物馆可以参观，服务热情贴心，早', '不愧为中国三大白金级酒店之一，环境优美，有花园和博物馆可以参观，服务热情贴心，早餐丰盛美味，除了床有些软，住感几乎完美。', '2023-03-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280a1e3c98b0941765def', '必须要给酒店一个大大的好评，尤其是前台一位染了头发的个子高高的男生（抱歉忘记了他的姓名）和当时在的主管。
我当时通过携程订的房间，到达前台的时候因为晕机+晕车非常不舒服。结果携程的预订出了问题，当时前台查不到我的订单。这位男生帮我查了很久，看我不舒服先请我在旁边坐下。后来联系携程，好容易订单重新弄好后居然又把我姓名弄错。折腾了好一阵才弄好住宿。
这位男生从头到尾态度非常好，看我带着行李和娃，还有送水。后来还请示主管帮我把房间升级，也送了小礼物。整个过程前台的男生和主管态度都非常好。其实这本来完全不是酒店的问题，但是酒店的态度实在是很令人满意。
于是后来我取消了原本订好的酒店，续住下去。
酒店本身其实有点老，但是交通的确非常方便。周围美食也很多。
后来走的时候又忘记东西在酒店，酒店也专门发了短信来提醒。
服务足以弥补硬件的问题。
酒店的洗漱台非常有特色，在极其有限的空间里营造出了德罗斯特效应。', '["https://dimg04.c-ctrip.com/images/0231n12000anycbff4562_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000anyiean1C95_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000anyf59uD31F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-02-13', '花园双床房', '双床房', '家庭亲子', 401, 5.996452088619021, 0, 0.0, 4, 1.6094379124341005, 9, '["前台服务", "交通便利性", "周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '必须要给酒店一个大大的好评，尤其是前台一位染了头发的个子高高的男生（抱歉忘记了他', '必须要给酒店一个大大的好评，尤其是前台一位染了头发的个子高高的男生（抱歉忘记了他的姓名）和当时在的主管。
我当时通过携程订的房间，到达前台的时候因为晕机+晕车非常不舒服。结果携程的预订出了问题，当时前台查不到我的订单。这位男生帮我查了很久，看我不舒服先请我在旁边坐下。后来联系携程，好容易订单重新弄好后居然又把我姓名弄错。折腾了好一阵才弄好住宿。
这位男生从头到尾态度非常好，看我带着行李和娃，还有送水。后来还请示主管帮我把房间升级，也送了小礼物。整个过程前台的男生和主管态度都非常好。其实这本来完全不是酒店的问题，但是酒店的态度实在是很令人满意。
于是后来我取消了原本订好的酒店，续住下去。
