INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280b6e3c98b0941765e01', '不愧为国家首批五星级酒店，接待服务一流！大堂办理入住的 Gillian非常热情，给我们免费升级到套房。设施齐全，卫生整洁，床品舒适，交通方便，小花园环境优美，特别是米其林美食非常好。下次再来广州还住这里。', '["https://dimg04.c-ctrip.com/images/0236412000dwonr182E2A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000dwonuvt097E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000dwontl83A3F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000dwonvws4D7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-07', '红棉双床套房', '套房', '其他', 102, 4.634728988229636, 0, 0.0, 3, 1.3862943611198906, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '不愧为国家首批五星级酒店，接待服务一流！大堂办理入住的 Gillian非常热情，', '不愧为国家首批五星级酒店，接待服务一流！大堂办理入住的 Gillian非常热情，给我们免费升级到套房。设施齐全，卫生整洁，床品舒适，交通方便，小花园环境优美，特别是米其林美食非常好。下次再来广州还住这里。', '2024-05-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280b6e3c98b0941765e02', '经常来广州，入住都是选择花园酒店，大堂大气，布置的也非常精美好看，前台同事办理入住迅速，房间卫生干净，退房接收到大堂经理lavinia的回访，询问入住体验很贴心。', '["https://dimg04.c-ctrip.com/images/0235512000etjvo9t2D15_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-18', '花园双床房', '双床房', '朋友出游', 81, 4.406719247264253, 0, 0.0, 3, 1.3862943611198906, 8, '["前台服务", "卫生状况", "整体满意度"]'::jsonb, '前台服务', '卫生状况', '整体满意度', '未知酒店', '未知地点', '匿名', '经常来广州，入住都是选择花园酒店，大堂大气，布置的也非常精美好看，前台同事办理入', '经常来广州，入住都是选择花园酒店，大堂大气，布置的也非常精美好看，前台同事办理入住迅速，房间卫生干净，退房接收到大堂经理lavinia的回访，询问入住体验很贴心。', '2024-07-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280b6e3c98b0941765e03', '非常满意，Zoey很热情', '["https://dimg04.c-ctrip.com/images/0231h12000bbu9o8b8111_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-31', '花园双床房', '双床房', '商务出差', 12, 2.5649493574615367, 0, 0.0, 2, 1.0986122886681098, 4, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '非常满意，Zoey很热情', '非常满意，Zoey很热情', '2023-05-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280c7e3c98b0941765e04', '整体都很满意，酒店环境服务都很棒，每个服务员都笑意盈盈，时刻打招呼和询问需求，特别是前台Viria，得知我带父母来游玩，怕老人家舍不得特别给免了加床费，每天的欢迎甜点也很棒，正值中秋还特别准备了小??，唯一美中不足的是酒店手持花洒水温很不稳定，t忽冷忽烫，不知是不是单一间房的问题，老人家洗完澡第二天就感冒发烧了，影响了部分行程，除此之外都挺好', '["https://dimg04.c-ctrip.com/images/0233o12000ca2gdu96686_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236h12000ca2pksn413E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000ca2kupm3356_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-29', '红棉双床套房', '套房', '家庭亲子', 172, 5.153291594497779, 0, 0.0, 12, 2.5649493574615367, 9, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '整体都很满意，酒店环境服务都很棒，每个服务员都笑意盈盈，时刻打招呼和询问需求，特', '整体都很满意，酒店环境服务都很棒，每个服务员都笑意盈盈，时刻打招呼和询问需求，特别是前台Viria，得知我带父母来游玩，怕老人家舍不得特别给免了加床费，每天的欢迎甜点也很棒，正值中秋还特别准备了小??，唯一美中不足的是酒店手持花洒水温很不稳定，t忽冷忽烫，不知是不是单一间房的问题，老人家洗完澡第二天就感冒发烧了，影响了部分行程，除此之外都挺好', '2023-09-29', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280c7e3c98b0941765e05', '作为80年代建成的第一批酒店，到现在还能吸引网红去打卡，可谓经久不衰。酒店充满岭南特色，园林精致，标志性景点18米双瀑布飞流直下，洞里惊现观音像，博物馆记录了酒店行业发展史，专业布置不输省博。比很多酒店都宽敞的健身房、25米游泳池，自由商务办公区，都非常不错。荔湾亭供应的早餐十分丰富，就是有的点心蒸的时间不够，还可以改善。
6.1儿童节入住，特别感谢前台小姐姐Suki的细心接待，帮考虑了老人小孩的需求，安排了全家都满意的红棉套房。', '["https://dimg04.c-ctrip.com/images/0236a12000bcg80fi9E6F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000bcgejglF6D7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000bcg3hc37CF4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000bcg731z4EAD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000bcg3j2c4159_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000bcg3hc53475_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-06-03', '花园双床房', '双床房', '家庭亲子', 217, 5.384495062789089, 0, 0.0, 5, 1.791759469228055, 9, '["公共设施", "餐饮设施", "前台服务"]'::jsonb, '公共设施', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '作为80年代建成的第一批酒店，到现在还能吸引网红去打卡，可谓经久不衰。酒店充满岭', '作为80年代建成的第一批酒店，到现在还能吸引网红去打卡，可谓经久不衰。酒店充满岭南特色，园林精致，标志性景点18米双瀑布飞流直下，洞里惊现观音像，博物馆记录了酒店行业发展史，专业布置不输省博。比很多酒店都宽敞的健身房、25米游泳池，自由商务办公区，都非常不错。荔湾亭供应的早餐十分丰富，就是有的点心蒸的时间不够，还可以改善。
6.1儿童节入住，特别感谢前台小姐姐Suki的细心接待，帮考虑了老人小孩的需求，安排了全家都满意的红棉套房。', '2023-06-03', 4, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280c7e3c98b0941765e06', '广州花园酒店不愧为中国唯三的白金五星级酒店，1985年开业的酒店到最近的装修，后花园贝大师30年前的设计，现在都不过时。广州的米其林餐厅炳胜公馆、江，味道不错。', '["https://dimg04.c-ctrip.com/images/0236k12000ahq8kd8B5E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000ahq87as61B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000ahq7iboB5E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237212000ahqaz6sE33C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000ahq7uw681FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000ahqa92g8014_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-23', '花园大床房', '大床房', '家庭亲子', 80, 4.394449154672439, 0, 0.0, 34, 3.555348061489413, 7, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '广州花园酒店不愧为中国唯三的白金五星级酒店，1985年开业的酒店到最近的装修，后', '广州花园酒店不愧为中国唯三的白金五星级酒店，1985年开业的酒店到最近的装修，后花园贝大师30年前的设计，现在都不过时。广州的米其林餐厅炳胜公馆、江，味道不错。', '2023-01-23', 5, '餐饮设施');
